-- ----------------------------------------------------------------------------
-- vw_loops: Table: Loops — build history and forward plan, carried as a first-class entity inside the model. Each row documents what new concept is introduced, what was witnessed, and (for planned rows) the next empirical question. Loops 62–67 are the corpus-scale research sweep + catalog expansion. Loops 68+ are the expansion encode waves: pre-register in DiscoveryHypotheses, encode via StudyImportTemplate, LoopReview at end of each turn before committing vocabulary.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_loops CASCADE;
CREATE VIEW vw_loops WITH (security_invoker = ON) AS
SELECT
  t.loop_id,                                                                    -- Unique identifier: loop-01 through loop-10.
  calc_loops_name(t.loop_id) AS name,                                           -- Display label.
  t.title,                                                                      -- Short title for what this loop adds to the domain model.
  t.status,                                                                     -- planned | in-progress | complete
  t.new_concept,                                                                -- The new first-class domain concept introduced this loop.
  t.domain_question,                                                            -- The natural-language question this loop's concept answers FROM the domain data.
  t.mock_data_note,                                                             -- What the seed data is designed to show.
  t.next_suggestion,                                                            -- Suggestion for the next loop, written after witnessing the DAG at this loop's end.
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose conceptual vocabulary this loop primarily draws on — tracks which tradition has driven each stage of the instrument's development.
  calc_loops_tradition_name(t.loop_id) AS tradition_name,                       -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_loops_tradition_core_conern(t.loop_id) AS tradition_core_conern,         -- Lookup: ResearchTraditions.CoreConcern via TraditionId — which intellectual concern drove this loop.
  t.commit_hash,                                                                -- Full git SHA where this loop row first landed in effortless-rulebook.json — the replay anchor for this turn of the Leopold loop.
  calc_loops_commit_short(t.loop_id) AS commit_short,                           -- First 7 characters of CommitHash for display and git checkout.
  t.commit_date,                                                                -- ISO date (YYYY-MM-DD) of the commit where this loop landed.
  t.commit_message,                                                             -- Git commit subject line for this loop's landing commit.
  t.git_tag                                                                     -- Optional milestone tag pointing at this loop's landing commit (sp-loop-milestone-*). Used for discovery replay without memorizing SHAs.
FROM loops t;

-- ----------------------------------------------------------------------------
-- vw_studies: Table: Studies — a clinical or empirical study comparing two or more treatments for a condition, with patient cases stratified by a confounding variable. The top-level entity in the domain.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_studies CASCADE;
CREATE VIEW vw_studies WITH (security_invoker = ON) AS
SELECT
  t.study_id,                                                                   -- Unique slug for this study (e.g. kidney-1986, berkeley-1973).
  calc_studies_name(t.study_id) AS name,                                        -- Display label, mirrors StudyId.
  t.title,                                                                      -- Human-readable title of the study.
  t.source,                                                                     -- Citation or description of the original data source.
  t.source_url,                                                                 -- URL to the original source.
  t.publication_year,                                                           -- Year the study was published. Used for temporal stratification and pre-registration dating.
  t.domain,                                                                     -- Research domain: medicine | epidemiology | social-science | education | legal | sports | economics | synthetic. Enables cross-domain SignalPurity stratification.
  t.is_synthetic,                                                               -- TRUE for constructed/counterfactual studies; FALSE for real published studies. Filters the corpus for empirical claims.
  calc_studies_total_cases(t.study_id) AS total_cases,                          -- Total number of cases (trials) across all CaseCells in this study.
  calc_studies_cell_count(t.study_id) AS cell_count,                            -- Number of CaseCell rows for this study.
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose framing best characterizes this study's paradox type. Synthetic studies inherit the tradition of their conceptual origin.
  t.primary_researcher_id,                                                      -- FK → Researchers.ResearcherId. The researcher most associated with first surfacing or canonically citing this study in the Simpson's Paradox literature.
  calc_studies_tradition_name(t.study_id) AS tradition_name,                    -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_studies_tradition_core_conern(t.study_id) AS tradition_core_conern,      -- Lookup: ResearchTraditions.CoreConcern via TraditionId.
  calc_studies_primary_researcher_name(t.study_id) AS primary_researcher_name,  -- Lookup: Researchers.Name via PrimaryResearcherId.
  calc_studies_primary_researcher_affiliation(t.study_id) AS primary_researcher_affiliation,-- Lookup: Researchers.Affiliation via PrimaryResearcherId.
  calc_studies_distortion_type(t.study_id) AS distortion_type,                  -- Lookup: TreatmentRankings.DistortionType for this study — the geometric classification of its paradox.
  calc_studies_policy_implication(t.study_id) AS policy_implication,            -- Lookup: TreatmentRankings.CorrectedPolicyImplication for this study.
  calc_studies_allocation_distortion(t.study_id) AS allocation_distortion,      -- Lookup: TreatmentRankings.AllocationDistortion for this study — the scalar severity of allocation-induced distortion.
  calc_studies_signal_purity(t.study_id) AS signal_purity,                      -- Lookup: TreatmentRankings.SignalPurity for this study — ratio of true signal to total gap width.
  calc_studies_is_sign_flip(t.study_id) AS is_sign_flip,                        -- Lookup: TreatmentRankings.IsSignFlip for this study — true if the paradox satisfies the continuous sign-flip definition.
  calc_studies_corrected_winner(t.study_id) AS corrected_winner,                -- Lookup: TreatmentRankings.CorrectedWinner for this study — which treatment wins after allocation correction.
  calc_studies_confounding_variable(t.study_id) AS confounding_variable,        -- Lookup: StratumVariables.VariableName for this study — the named stratifying variable.
  calc_studies_causal_role(t.study_id) AS causal_role,                          -- Lookup: StratumVariables.CausalRole for this study — confounder, mediator, collider, proxy, or contested.
  calc_studies_ingestion_cell_parity(t.study_id) AS ingestion_cell_parity,      -- TRUE when CellCount = 2 x StratumCount.
  calc_studies_ingestion_compliance(t.study_id) AS ingestion_compliance,        -- all | partial | exempt-synthetic.
  t.is_control_study,                                                           -- TRUE if this study is a control (no Simpson's paradox expected/found); FALSE for the main Simpson's Paradox corpus.
  t.control_domain,                                                             -- Domain slug for control studies (e.g. medicine-rct, education-higher). NULL for non-control studies.
  t.valid_time_start,                                                           -- First year of the real-world cohort period this study's data covers (valid-time, not publication year). Defaults to PublicationYear when the true cohort window is not independently known.
  t.valid_time_end,                                                             -- Last year of the real-world cohort period this study's data covers (valid-time, not publication year). Defaults to PublicationYear when the true cohort window is not independently known.
  calc_studies_valid_time_midpoint(t.study_id) AS valid_time_midpoint,          -- Midpoint year of the valid-time cohort window, used to bucket studies by when their underlying data actually occurred rather than when the paper was published.
  calc_studies_valid_time_decade(t.study_id) AS valid_time_decade               -- ValidTimeMidpoint floored to the decade (e.g. 1973 -> 1970). The bucket key ConfounderDistortionTimeline aggregates over.
FROM studies t;

-- ----------------------------------------------------------------------------
-- vw_treatments: Table: Treatments — the interventions being compared within a study. Each treatment belongs to one study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatments CASCADE;
CREATE VIEW vw_treatments WITH (security_invoker = ON) AS
SELECT
  t.treatment_id,                                                               -- Unique slug (e.g. kidney-1986-A, kidney-1986-B).
  calc_treatments_name(t.treatment_id) AS name,                                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.treatment_label,                                                            -- Short label used in CaseCells and comparisons (e.g. A, B).
  t.description,                                                                -- Plain-language description of what this treatment is.
  calc_treatments_total_cases(t.treatment_id) AS total_cases,                   -- Total cases for this treatment across all strata.
  calc_treatments_total_successes(t.treatment_id) AS total_successes,           -- Total successes for this treatment across all strata.
  calc_treatments_pooled_success_rate(t.treatment_id) AS pooled_success_rate    -- Pooled (across all strata) success rate for this treatment: TotalSuccesses / TotalCases.
FROM treatments t;

-- ----------------------------------------------------------------------------
-- vw_strata: Table: Strata — the subdivisions of patients within a study by the value of the confounding variable (e.g. stone size). Each stratum belongs to one study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_strata CASCADE;
CREATE VIEW vw_strata WITH (security_invoker = ON) AS
SELECT
  t.stratum_id,                                                                 -- Unique slug (e.g. kidney-1986-small, kidney-1986-large).
  calc_strata_name(t.stratum_id) AS name,                                       -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- Short label used in CaseCells (e.g. small, large, dept-A).
  t.description,                                                                -- Plain-language description of what defines this stratum.
  calc_strata_total_cases(t.stratum_id) AS total_cases                          -- Total cases in this stratum across all treatments.
FROM strata t;

-- ----------------------------------------------------------------------------
-- vw_case_cells: Table: CaseCells — the raw leaves of the DAG. One row per (study, stratum, treatment) combination recording the aggregate count of successes and total cases. Every derived fact in the model traces back to these numbers. Nothing above this row is a raw input.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_case_cells CASCADE;
CREATE VIEW vw_case_cells WITH (security_invoker = ON) AS
SELECT
  t.case_cell_id,                                                               -- Unique slug (e.g. kidney-1986-small-A).
  calc_case_cells_name(t.case_cell_id) AS name,                                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- The stratum this cell belongs to (matches Strata.StratumLabel).
  t.treatment_label,                                                            -- The treatment applied in this cell (matches Treatments.TreatmentLabel).
  t.successes,                                                                  -- Number of patients in this cell who had a successful outcome. RAW INPUT — never derived.
  t.cases,                                                                      -- Total number of patients in this cell. RAW INPUT — never derived.
  calc_case_cells_cell_success_rate(t.case_cell_id) AS cell_success_rate,       -- Success rate within this cell: Successes / Cases. The first derived fact in the DAG. Fixed loop-90: this rulebook's IF(x=0,"",...) idiom transpiles to a bare ''::numeric cast that errors at runtime for the one CaseCells row with Cases=0 (surfaced only once _erb_tr_metrics stopped masking it). Returns 0 for the degenerate zero-cases cell instead.
  calc_case_cells_total_cases_for_treatment(t.case_cell_id) AS total_cases_for_treatment,-- Total cases across ALL strata for this treatment in this study — the denominator for TreatmentExposureFraction.
  calc_case_cells_treatment_exposure_fraction(t.case_cell_id) AS treatment_exposure_fraction,-- Fraction of this treatment's total cases that fall in this stratum: Cases / TotalCasesForTreatment. High imbalance across strata is the mechanism of confounding — when treatments are allocated very differently across strata, the pooled rate conflates treatment effect with stratum difficulty.
  calc_case_cells_is_valid_ingestion_cell(t.case_cell_id) AS is_valid_ingestion_cell-- TRUE when Cases>=0, Successes>=0, and Successes<=Cases (loop-92: a stratum-treatment combination can legitimately have zero observed cases in real source data -- e.g. rdatasets-mtcars-engine has zero 8-cylinder straight-engine cars -- so Cases=0 is a valid ingestion cell, not a defect).
FROM case_cells t;

-- ----------------------------------------------------------------------------
-- vw_stratum_summaries: Table: StratumSummaries — one row per (study, stratum, treatment). Computes the success rate WITHIN each stratum for each treatment. This is the stratified view that contradicts the pooled conclusion when a Simpson's Paradox reversal is present. Each row belongs to both a Stratum and a Treatment in the same Study.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stratum_summaries CASCADE;
CREATE VIEW vw_stratum_summaries WITH (security_invoker = ON) AS
SELECT
  t.stratum_summary_id,                                                         -- Unique slug (e.g. kidney-1986-small-A).
  calc_stratum_summaries_name(t.stratum_summary_id) AS name,                    -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.stratum_label,                                                              -- Which stratum (matches Strata.StratumLabel).
  t.treatment_label,                                                            -- Which treatment (matches Treatments.TreatmentLabel).
  calc_stratum_summaries_stratum_successes(t.stratum_summary_id) AS stratum_successes,-- Total successes in this (stratum, treatment) cell for this study.
  calc_stratum_summaries_stratum_cases(t.stratum_summary_id) AS stratum_cases,  -- Total cases in this (stratum, treatment) cell for this study.
  calc_stratum_summaries_stratum_success_rate(t.stratum_summary_id) AS stratum_success_rate,-- Success rate within this stratum for this treatment: StratumSuccesses / StratumCases. The true per-stratum picture.
  calc_stratum_summaries_stratum_successes_a(t.stratum_summary_id) AS stratum_successes_a,-- Successes for treatment A in this (study, stratum) — used to determine the per-stratum winner.
  calc_stratum_summaries_stratum_cases_a(t.stratum_summary_id) AS stratum_cases_a,-- Cases for treatment A in this (study, stratum).
  calc_stratum_summaries_stratum_rate_a(t.stratum_summary_id) AS stratum_rate_a,-- Success rate for treatment A in this stratum.
  calc_stratum_summaries_stratum_successes_b(t.stratum_summary_id) AS stratum_successes_b,-- Successes for treatment B in this (study, stratum).
  calc_stratum_summaries_stratum_cases_b(t.stratum_summary_id) AS stratum_cases_b,-- Cases for treatment B in this (study, stratum).
  calc_stratum_summaries_stratum_rate_b(t.stratum_summary_id) AS stratum_rate_b,-- Success rate for treatment B in this stratum.
  calc_stratum_summaries_stratum_winner(t.stratum_summary_id) AS stratum_winner,-- Which treatment wins in this stratum: 'A' if StratumRateA > StratumRateB, else 'B'. Used by TreatmentRankings to detect paradox.
  calc_stratum_summaries_study_total_cases(t.stratum_summary_id) AS study_total_cases,-- Total cases across ALL strata and ALL treatments in this study. The denominator for StratumFraction.
  calc_stratum_summaries_stratum_total_cases(t.stratum_summary_id) AS stratum_total_cases,-- Total cases in this stratum across both treatments (A + B combined). Numerator for StratumFraction.
  calc_stratum_summaries_stratum_fraction(t.stratum_summary_id) AS stratum_fraction,-- Fraction of the study's total cases that fall in this stratum: StratumTotalCases / StudyTotalCases. The weight the confounder assigns to each stratum. A large StratumFraction on a low-success stratum pulls the pooled rate down; when that stratum is also over-allocated to one treatment, it creates the reversal.
  calc_stratum_summaries_weighted_stratum_rate(t.stratum_summary_id) AS weighted_stratum_rate,-- StratumFraction × StratumSuccessRate. The contribution of this (stratum, treatment) row to the study-level pooled rate. Summing WeightedStratumRate across all strata for a given treatment reconstructs that treatment's pooled rate from stratum weights — witnessing the mechanism equation.
  calc_stratum_summaries_treatment_a_cases_here(t.stratum_summary_id) AS treatment_a_cases_here,-- Cases for treatment A in this stratum — used to compute TreatmentA's allocation fraction in this stratum.
  calc_stratum_summaries_treatment_b_cases_here(t.stratum_summary_id) AS treatment_b_cases_here,-- Cases for treatment B in this stratum — used to compute TreatmentB's allocation fraction in this stratum.
  calc_stratum_summaries_treatment_a_total_cases(t.stratum_summary_id) AS treatment_a_total_cases,-- Total cases for treatment A across all strata in this study — denominator for AllocationFractionA.
  calc_stratum_summaries_treatment_b_total_cases(t.stratum_summary_id) AS treatment_b_total_cases,-- Total cases for treatment B across all strata in this study — denominator for AllocationFractionB.
  calc_stratum_summaries_allocation_fraction_a(t.stratum_summary_id) AS allocation_fraction_a,-- Fraction of treatment A's total cases that land in this stratum: TreatmentACasesHere / TreatmentATotalCases. Equivalent to TreatmentExposureFraction for A.
  calc_stratum_summaries_allocation_fraction_b(t.stratum_summary_id) AS allocation_fraction_b,-- Fraction of treatment B's total cases that land in this stratum: TreatmentBCasesHere / TreatmentBTotalCases.
  calc_stratum_summaries_allocation_bias(t.stratum_summary_id) AS allocation_bias,-- AllocationFractionA minus AllocationFractionB: how much more of treatment A (relative to B) is concentrated in this stratum. Positive = A is over-allocated here; negative = B is over-allocated here. When AllocationBias is large and negative in a low-success stratum, treatment A is under-represented in the hard cases — making A look worse in the pooled view than it is in any stratum. This is the confounder's fingerprint as a signed number.
  calc_stratum_summaries_stratum_gap(t.stratum_summary_id) AS stratum_gap,      -- Signed rate difference within this stratum: StratumRateA minus StratumRateB. Positive = A wins here; negative = B wins here; zero = tied. When every stratum has StratumGap > 0 but the pooled gap is negative, the contradiction IS Simpson's Paradox made arithmetically visible in one column. Multiply StratumGap × StratumFraction and sum across strata to get the equal-weight pooled gap (the signal allocation would produce without confounding).
  calc_stratum_summaries_weighted_stratum_gap(t.stratum_summary_id) AS weighted_stratum_gap,-- StratumGap × StratumFraction: the contribution of this stratum's treatment-rate difference to the equal-weight pooled gap. Summing WeightedStratumGap across all TreatmentA rows for a study gives WeightedStratumGapSum — the pooled gap the study would show under balanced allocation. This is the per-stratum building block of the sign-flip test.
  calc_stratum_summaries_abs_allocation_bias(t.stratum_summary_id) AS abs_allocation_bias,-- ABS(AllocationBias). MAXIFS-friendly unsigned magnitude so TreatmentRankings.MaxStratumImbalance can compute live via MAXIFS instead of a hand-written cache.
  calc_stratum_summaries_abs_stratum_gap(t.stratum_summary_id) AS abs_stratum_gap-- ABS(StratumGap). MAXIFS-friendly unsigned magnitude so TreatmentRankings.MaxStratumGap can compute live via MAXIFS instead of a hand-written cache.
FROM stratum_summaries t;

-- ----------------------------------------------------------------------------
-- vw_model_summary: Table: ModelSummary — one row describing the epistemic coverage of this entire model instance. Aggregates across all TreatmentRankings to witness how many studies were examined, how many showed a full reversal, how many were explained, and the average paradox strength. The model holds a mirror to itself.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_model_summary CASCADE;
CREATE VIEW vw_model_summary WITH (security_invoker = ON) AS
SELECT
  t.model_summary_id,                                                           -- Unique identifier for this model instance.
  calc_model_summary_name(t.model_summary_id) AS name,                          -- Display label.
  calc_model_summary_reversal_count(t.model_summary_id) AS reversal_count,      -- Number of studies with IsReversal=TRUE (sign-flip / allocation-driven reversal).
  calc_model_summary_non_reversal_count(t.model_summary_id) AS non_reversal_count,-- Number of studies with IsReversal=FALSE.
  calc_model_summary_study_count(t.model_summary_id) AS study_count,            -- Total number of TreatmentRankings in this model: ReversalCount + NonReversalCount.
  calc_model_summary_explained_count(t.model_summary_id) AS explained_count,    -- Number of studies with IsParadoxExplained=TRUE (reversal AND confirmed confounder).
  calc_model_summary_total_paradox_strength(t.model_summary_id) AS total_paradox_strength,-- Sum of ParadoxStrength across all studies. Used to compute average.
  calc_model_summary_avg_paradox_strength(t.model_summary_id) AS avg_paradox_strength,-- Average ParadoxStrength across all studies: TotalParadoxStrength / StudyCount. A scalar summary of how paradox-rich this dataset is.
  calc_model_summary_type_a_count(t.model_summary_id) AS type_a_count,          -- Studies classified as Type-A: sign flip AND full reversal (ReversalIntensity=1). The canonical Simpson's Paradox — allocation distortion reverses the pooled winner.
  calc_model_summary_danger_tier_count(t.model_summary_id) AS danger_tier_count,-- Studies where TreatmentRankings.ScreeningTier = DANGER — pooled sign is wrong (DistortionType A or B).
  calc_model_summary_caution_tier_count(t.model_summary_id) AS caution_tier_count,-- Studies where TreatmentRankings.ScreeningTier = CAUTION — pooled sign holds but magnitude is distorted (DistortionType C+ or C-).
  calc_model_summary_safe_tier_count(t.model_summary_id) AS safe_tier_count,    -- Studies where TreatmentRankings.ScreeningTier = SAFE — pooling is trustworthy (DistortionType D).
  calc_model_summary_type_b_count(t.model_summary_id) AS type_b_count,          -- Studies classified as Type-B: sign flip but partial reversal (ReversalIntensity<1). Allocation distortion creates a sign flip but the pooled signal partially reflects per-stratum reality.
  calc_model_summary_type_d_count(t.model_summary_id) AS type_d_count,          -- Studies classified as Type-D: no sign flip, negligible distortion. Pooled analysis is trustworthy — allocation is sufficiently balanced.
  calc_model_summary_type_a_fraction(t.model_summary_id) AS type_a_fraction,    -- Fraction of studies that are Type-A (full canonical reversals). TypeACount / StudyCount.
  calc_model_summary_distortion_taxonomy_coverage(t.model_summary_id) AS distortion_taxonomy_coverage,-- Human-readable summary of the four-type distribution: e.g. 'A:2 B:1 C:1 D:0'. The model's self-portrait of its own distortion geometry.
  calc_model_summary_distortion_only_count(t.model_summary_id) AS distortion_only_count,-- Number of studies with real allocation distortion but no sign flip: TypeCCount. The pooled winner is correct but the effect size is biased. Distinct from ZeroStrengthCount, which conflates Type-C (real distortion) with Type-D (neutral).
  calc_model_summary_c_amplification_count(t.model_summary_id) AS c_amplification_count,-- Number of studies classified as type C+ (allocation-amplified): pooled winner is correct but pooled gap overstates true advantage. Causes researcher overconfidence — may accept higher cost/risk than true effect warrants.
  calc_model_summary_c_compression_count(t.model_summary_id) AS c_compression_count,-- Number of studies classified as type C- (allocation-compressed): pooled winner is correct but pooled gap understates true advantage. Causes researcher underconfidence — effective treatment may be prematurely abandoned.
  calc_model_summary_avg_signal_purity(t.model_summary_id) AS avg_signal_purity,-- Average SignalPurity across all TreatmentRankings. Below 0.5 means allocation noise exceeds true signal on average — the corpus is predominantly misleading at the pooled level. Above 0.5 means the corpus is predominantly trustworthy. Fixed loop-90: COUNTIFS(...,"<>")/SUMIFS(...,"<>") mistranslate to a literal '<>' string-equality filter (a known transpiler bug), always returning 0/NULL; replaced with SUM/COUNT, both of which transpile correctly.
  calc_model_summary_sweep_corrected_gap_max(t.model_summary_id) AS sweep_corrected_gap_max,-- Maximum SweepCorrectedGap across all AllocationSweep rows. Should equal SweepCorrectedGapMin — the invariant.
  calc_model_summary_sweep_corrected_gap_min(t.model_summary_id) AS sweep_corrected_gap_min,-- Minimum SweepCorrectedGap across all AllocationSweep rows. Should equal SweepCorrectedGapMax — the invariant.
  calc_model_summary_sweep_corrected_gap_range(t.model_summary_id) AS sweep_corrected_gap_range,-- SweepCorrectedGapMax − SweepCorrectedGapMin. The allocation-invariance witness: this should be zero (up to floating-point rounding). If nonzero, the corrected gap is not allocation-free.
  calc_model_summary_sweep_pooled_gap_range(t.model_summary_id) AS sweep_pooled_gap_range,-- MAX(SweepPooledGap) − MIN(SweepPooledGap) across all AllocationSweep rows. Expected to be large (≈0.21) — the pooled gap wanders as allocation shifts.
  calc_model_summary_real_study_count(t.model_summary_id) AS real_study_count,  -- Number of real (non-synthetic) published studies in the corpus. Retyped loop-90: was mis-declared raw with a formula, which is why the transpiler emitted no native function and 02b had to hand-write calc_model_summary_real_study_count.
  calc_model_summary_avg_signal_purity_reversal(t.model_summary_id) AS avg_signal_purity_reversal,-- Average SignalPurity across reversal studies (type A and B). Theorem predicts this must be < 0.5. Retyped loop-90 (see RealStudyCount); rewritten from SUMIFS/COUNTIFS division to AVERAGEIFS because the SUMIFS/COUNTIFS division form transpiled with a mangled cross-table alias.
  calc_model_summary_avg_signal_purity_non_reversal(t.model_summary_id) AS avg_signal_purity_non_reversal,-- Average SignalPurity across non-reversal studies (type C+, C-, D). Theorem predicts this must be >= 0.5 except edge cases. Retyped loop-90 (see RealStudyCount); rewritten from SUMIFS/COUNTIFS division to AVERAGEIFS (see AvgSignalPurityReversal).
  calc_model_summary_signal_purity_gap(t.model_summary_id) AS signal_purity_gap,-- Separation between reversal and non-reversal average SignalPurity. The larger this gap, the more discriminating the threshold at 0.5. Retyped loop-90 (see RealStudyCount).
  calc_model_summary_medicine_study_count(t.model_summary_id) AS medicine_study_count,-- Real published studies in the medicine domain. Retyped loop-90 (see RealStudyCount).
  calc_model_summary_epidemiology_study_count(t.model_summary_id) AS epidemiology_study_count,-- Real published studies in the epidemiology domain. Retyped loop-90 (see RealStudyCount).
  calc_model_summary_other_domain_study_count(t.model_summary_id) AS other_domain_study_count,-- Real published studies outside medicine and epidemiology (sports, legal, education, social-science). Retyped loop-90 (see RealStudyCount).
  calc_model_summary_domain_diversity_note(t.model_summary_id) AS domain_diversity_note,-- Human-readable domain breakdown. Witnesses corpus diversity — a prerequisite for cross-domain SignalPurity claims. Retyped loop-90 (see RealStudyCount); TEXT(...,"0%") is not a supported transpiler function, replaced with ROUND(x*100,0) + literal '%'.
  t.synthetic_phase_count,                                                      -- Number of parameter grid points in SyntheticPhase. Refreshed from vw_phase_diagram_summary by 05b-customize-data.sql.
  t.phase_diagram_complete,                                                     -- TRUE when all five DistortionType cells are populated in the synthetic phase grid. Refreshed from vw_phase_diagram_summary by 05b.
  t.phase_taxonomy_coverage,                                                    -- Type counts across the synthetic phase grid. Refreshed from vw_phase_diagram_summary by 05b.
  calc_model_summary_ingestion_protocol_item_count(t.model_summary_id) AS ingestion_protocol_item_count,-- Number of rows in IngestionProtocol — the documented contract items. Fixed loop-90 (see IngestionSummary.ProtocolItemCount for why COUNTIFS(...,"<>") is unsafe).
  calc_model_summary_corpus_passes_ingestion_contract(t.model_summary_id) AS corpus_passes_ingestion_contract,-- Lookup: IngestionSummary.IngestionContractPasses.
  calc_model_summary_ingestion_witness_note(t.model_summary_id) AS ingestion_witness_note,-- Human-readable ingestion contract witness from IngestionSummary.
  calc_model_summary_catalog_entry_count(t.model_summary_id) AS catalog_entry_count,-- Total catalog rows.
  calc_model_summary_pending_import_count(t.model_summary_id) AS pending_import_count,-- Candidate studies queued.
  calc_model_summary_ready_to_encode_count(t.model_summary_id) AS ready_to_encode_count,-- Encode-ready candidates.
  calc_model_summary_import_session_ready(t.model_summary_id) AS import_session_ready,-- Bulk import session readiness flag.
  calc_model_summary_catalog_witness_note(t.model_summary_id) AS catalog_witness_note,-- Import backlog witness string.
  calc_model_summary_latent_type_d_count(t.model_summary_id) AS latent_type_d_count,-- Type-D studies with LatentFlipPotential=TRUE.
  calc_model_summary_stable_type_d_count(t.model_summary_id) AS stable_type_d_count,-- Type-D studies without latent flip potential (allocation-stable at observed and counterfactual sweep).
  calc_model_summary_latent_type_d_fraction(t.model_summary_id) AS latent_type_d_fraction,-- Fraction of Type-D studies with latent flip potential.
  calc_model_summary_cross_zero_count(t.model_summary_id) AS cross_zero_count,  -- Studies whose pooled gap crosses zero under allocation sweep.
  calc_model_summary_sign_flip_signal_purity_max(t.model_summary_id) AS sign_flip_signal_purity_max,-- Maximum SignalPurity among sign-flip studies. Must stay below 0.5 for the signal-purity theorem.
  calc_model_summary_economics_sign_flip_count(t.model_summary_id) AS economics_sign_flip_count,-- Sign-flip count in economics domain.
  calc_model_summary_sum_pooled_gap_latent_d(t.model_summary_id) AS sum_pooled_gap_latent_d,-- SUM(PooledGap) among Type-D studies with latent flip potential — a bare, unwrapped SUMIFS split out as its own field because nesting a cross-table SUMIFS/AVERAGEIFS as an operand inside another IF/division expression transpiles with a mangled WHERE-clause column alias (e.g. rankings_latent_flip_potential) that errors at runtime; a bare top-level SUMIFS transpiles correctly (loop-90).
  calc_model_summary_avg_pooled_gap_latent_d(t.model_summary_id) AS avg_pooled_gap_latent_d,-- Average PooledGap among Type-D studies with latent flip potential. Fixed loop-90 (see SumPooledGapLatentD for why the sum is split into its own field).
  calc_model_summary_sum_pooled_gap_stable_d(t.model_summary_id) AS sum_pooled_gap_stable_d,-- SUM(PooledGap) among allocation-stable Type-D studies — split out as a bare field for the same reason as SumPooledGapLatentD.
  calc_model_summary_avg_pooled_gap_stable_d(t.model_summary_id) AS avg_pooled_gap_stable_d,-- Average PooledGap among allocation-stable Type-D studies. Fixed loop-90 (see SumPooledGapLatentD).
  calc_model_summary_epidemiology_avg_distortion(t.model_summary_id) AS epidemiology_avg_distortion,-- Mean AllocationDistortion in epidemiology studies.
  calc_model_summary_education_avg_distortion(t.model_summary_id) AS education_avg_distortion,-- Mean AllocationDistortion in education studies.
  calc_model_summary_confounder_sign_flip_count(t.model_summary_id) AS confounder_sign_flip_count,-- Sign-flip count among confounder-labeled studies.
  calc_model_summary_confounder_latent_only_count(t.model_summary_id) AS confounder_latent_only_count,-- Latent-only flip count among confounder-labeled studies.
  calc_model_summary_collider_selection_count(t.model_summary_id) AS collider_selection_count,-- Studies tagged collider or selection on StratumVariables.
  calc_model_summary_collider_selection_manifest_count(t.model_summary_id) AS collider_selection_manifest_count,-- Manifest sign-flips among collider/selection studies.
  calc_model_summary_collider_selection_latent_only_count(t.model_summary_id) AS collider_selection_latent_only_count,-- Latent-only flips among collider/selection studies.
  calc_model_summary_explained_confounder_count(t.model_summary_id) AS explained_confounder_count,-- Count of TreatmentRankings rows where IsParadoxExplained=TRUE (should equal ConfounderSignFlipCount).
  calc_model_summary_contested_or_mediator_explained_count(t.model_summary_id) AS contested_or_mediator_explained_count,-- Count of contested or mediator sign-flip rows where IsParadoxExplained=TRUE (should be zero).
  calc_model_summary_discovery_witness_note(t.model_summary_id) AS discovery_witness_note,-- Research sweep synthesis rollup (loops 61–66).
  calc_model_summary_type_prediction_match_count(t.model_summary_id) AS type_prediction_match_count,-- Lookup: CorpusCatalogSummary.TypePredictionMatchCount.
  calc_model_summary_type_prediction_mismatch_count(t.model_summary_id) AS type_prediction_mismatch_count,-- Lookup: CorpusCatalogSummary.TypePredictionMismatchCount.
  calc_model_summary_type_prediction_match_rate(t.model_summary_id) AS type_prediction_match_rate,-- Lookup: CorpusCatalogSummary.TypePredictionMatchRate.
  calc_model_summary_sign_flip_prediction_match_rate(t.model_summary_id) AS sign_flip_prediction_match_rate,-- Lookup: CorpusCatalogSummary.SignFlipPredictionMatchRate.
  calc_model_summary_catalog_prediction_witness_note(t.model_summary_id) AS catalog_prediction_witness_note,-- Lookup: CorpusCatalogSummary.CatalogPredictionWitnessNote.
  t.high_imbalance_sign_flip_threshold,                                         -- max_stratum_imbalance cutoff for geometry-controlled domain screening (loop-66). Set from corpus median by customize SQL.
  t.economics_high_imbalance_sign_flip_count,                                   -- Sign-flip count among economics studies with max_stratum_imbalance >= threshold.
