  t.legal_high_imbalance_sign_flip_rate,                                        -- Sign-flip rate among high-imbalance legal studies.
  t.sports_high_imbalance_sign_flip_rate,                                       -- Sign-flip rate among high-imbalance sports studies.
  calc_model_summary_c_plus_avg_distortion(t.model_summary_id) AS c_plus_avg_distortion,-- Mean AllocationDistortion among Type-C+ studies.
  calc_model_summary_c_minus_avg_distortion(t.model_summary_id) AS c_minus_avg_distortion,-- Mean AllocationDistortion among Type-C- studies.
  calc_model_summary_type_d_avg_distortion(t.model_summary_id) AS type_d_avg_distortion,-- Mean AllocationDistortion among Type-D studies.
  calc_model_summary_sweep_fragile_count(t.model_summary_id) AS sweep_fragile_count,-- Count of TreatmentRankings with IsSweepFragile=TRUE.
  calc_model_summary_expansion_wave1_economics_expected_a_count(t.model_summary_id) AS expansion_wave1_economics_expected_a_count,-- Imported expansion-wave-1 economics catalog rows tagged Expected A.
  calc_model_summary_expansion_wave1_economics_expected_ad_count(t.model_summary_id) AS expansion_wave1_economics_expected_ad_count,-- Expansion-wave-1 economics Expected-A imports observed as Type D.
  calc_model_summary_economics_expected_a_mismatch_rate(t.model_summary_id) AS economics_expected_a_mismatch_rate,-- Fraction of expansion-wave-1 economics Expected-A imports observed as Type D.
  calc_model_summary_unanimous_sign_flip_count(t.model_summary_id) AS unanimous_sign_flip_count,-- Sign-flip studies with unanimous stratum direction (IsSignFlip AND IsStratumUnanimous).
  calc_model_summary_max_study_sweep_corrected_gap_range(t.model_summary_id) AS max_study_sweep_corrected_gap_range,-- MAX(SweepStudySummary.SweepCorrectedGapRange) — must stay below 0.0001 for CorrectedGap invariance theorem.
  calc_model_summary_corrected_gap_invariant_fail_count(t.model_summary_id) AS corrected_gap_invariant_fail_count,-- Count of SweepStudySummary rows where SweepCorrectedGapRange >= 0.0001.
  calc_model_summary_false_positive_explained_count(t.model_summary_id) AS false_positive_explained_count,-- IsParadoxExplained=TRUE rows that are not confounder manifest sign-flips — must be 0 for explained↔confounder theorem.
  calc_model_summary_unexplained_confounder_sign_flip_count(t.model_summary_id) AS unexplained_confounder_sign_flip_count,-- Confounder sign-flips with IsParadoxExplained=FALSE — must be 0 for explained↔confounder theorem.
  calc_model_summary_theorem_count(t.model_summary_id) AS theorem_count,        -- Count of witnessed Conclusions with Category=corpus-theorem (portfolio rollup for loop-76; category renamed from theorem in loop-91).
  calc_model_summary_education_latent_fraction(t.model_summary_id) AS education_latent_fraction,-- Fraction of education Type-D studies with LatentFlipPotential=TRUE.
  calc_model_summary_sports_latent_fraction(t.model_summary_id) AS sports_latent_fraction,-- Fraction of sports Type-D studies with LatentFlipPotential=TRUE.
  calc_model_summary_economics_sign_flip_rate(t.model_summary_id) AS economics_sign_flip_rate,-- Manifest sign-flip rate among economics studies.
  calc_model_summary_education_type_d_count(t.model_summary_id) AS education_type_d_count,-- Type-D studies in education domain.
  calc_model_summary_education_latent_d_count(t.model_summary_id) AS education_latent_d_count,-- Education Type-D studies with LatentFlipPotential.
  calc_model_summary_sports_type_d_count(t.model_summary_id) AS sports_type_d_count,-- Type-D studies in sports domain.
  calc_model_summary_sports_latent_d_count(t.model_summary_id) AS sports_latent_d_count,-- Sports Type-D studies with LatentFlipPotential.
  calc_model_summary_economics_study_count(t.model_summary_id) AS economics_study_count,-- Real economics studies in corpus.
  calc_model_summary_expansion_wave2_study_count(t.model_summary_id) AS expansion_wave2_study_count,-- Studies imported in expansion wave 2.
  calc_model_summary_confounder_identity_count(t.model_summary_id) AS confounder_identity_count,-- Canonical ConfounderIdentity archetypes in ontology (loop-80).
  calc_model_summary_mapped_stratum_variable_count(t.model_summary_id) AS mapped_stratum_variable_count,-- Stratum variables with an identity map row.
  calc_model_summary_unmapped_stratum_variable_count(t.model_summary_id) AS unmapped_stratum_variable_count,-- Stratum variables lacking identity map (should be 0).
  calc_model_summary_age_identity_manifest_flip_rate(t.model_summary_id) AS age_identity_manifest_flip_rate,-- Manifest flip rate for id-age-composition cluster (loop-81).
  calc_model_summary_age_identity_study_count(t.model_summary_id) AS age_identity_study_count,-- Real-study count in id-age-composition cluster (loop-81).
  calc_model_summary_age_identity_latent_fraction_among_type_d(t.model_summary_id) AS age_identity_latent_fraction_among_type_d,-- Type-D latent fraction for id-age-composition cluster (loop-81).
  calc_model_summary_severity_identity_latent_fraction_among_type(t.model_summary_id) AS severity_identity_latent_fraction_among_type_d,-- Type-D latent fraction for id-disease-severity cluster (loop-81).
  calc_model_summary_identity_map_coverage_rate(t.model_summary_id) AS identity_map_coverage_rate,-- Fraction of real-study StratumVariables with a ConfounderIdentity map (loop-81 customize SQL).
  t.identity_cluster_witness_note,                                              -- Loop-80 identity layer witness rollup (customize SQL).
  calc_model_summary_severity_medicine_manifest_flip_rate(t.model_summary_id) AS severity_medicine_manifest_flip_rate,-- Severity identity manifest flip rate in medicine domain.
  calc_model_summary_severity_epi_manifest_flip_count(t.model_summary_id) AS severity_epi_manifest_flip_count,-- Severity identity manifest flip count in epidemiology domain.
  calc_model_summary_identity_domain_cell_count(t.model_summary_id) AS identity_domain_cell_count,-- Number of identity×domain cells.
  calc_model_summary_selection_frailty_manifest_flip_count(t.model_summary_id) AS selection_frailty_manifest_flip_count,-- Manifest flip count for selection-frailty identity.
  calc_model_summary_selection_frailty_study_count(t.model_summary_id) AS selection_frailty_study_count,-- Study count for selection-frailty identity cluster.
  calc_model_summary_collider_identity_manifest_flip_rate(t.model_summary_id) AS collider_identity_manifest_flip_rate,-- Manifest flip rate for collider-proxy identity.
  calc_model_summary_geographic_type_d_fraction(t.model_summary_id) AS geographic_type_d_fraction,-- Type-D fraction for geographic-composition identity.
  calc_model_summary_severity_drift_direction(t.model_summary_id) AS severity_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-disease-severity (severity-case-mix archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_geographic_drift_direction(t.model_summary_id) AS geographic_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-geographic-composition (geography archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_situational_drift_direction(t.model_summary_id) AS situational_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-situational-context (sports-situation archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_age_drift_direction(t.model_summary_id) AS age_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-age-composition (demographic-composition archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_institutional_drift_direction(t.model_summary_id) AS institutional_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-institutional-unit (organizational-unit archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_socioeconomic_drift_direction(t.model_summary_id) AS socioeconomic_drift_direction,-- loop-92: ConfounderDistortionTimeline.DriftDirection for id-socioeconomic-status (ses-income archetype), valid-time Type-D drift. Overridden in 02b-customize-functions.sql: native transpiler mistranslates LOOKUP(constant, Table[NonPKColumn], Table[TargetColumn]) into a lookup keyed on the table's PK instead of the specified match column.
  calc_model_summary_domain_flip_gap_survives_geometry_control(t.model_summary_id) AS domain_flip_gap_survives_geometry_control,-- TRUE when the economics-vs-epidemiology sign-flip-rate gap for H-domain-flip-geometry-controlled survives after restricting to high-imbalance studies (loop-90 native promotion of the former 02b hand function).
  calc_model_summary_corpus_pattern_superseded_fail_count(t.model_summary_id) AS corpus_pattern_superseded_fail_count,-- Count of DiscoveryFindings rows for the 6 superseded-pattern hypotheses (H-econ-zero, H-domain-dist, H-catalog-flip-prediction, H-domain-flip-geometry-controlled, H-econ-encoding-selection, H-domain-profiles-stable) where IsConfirmed=FALSE. Six separate COUNTIFS summed with '+' because this rulebook's formula vocabulary has no IN-list/pipe-delimited OR criterion for COUNTIFS (loop-90 native promotion of the former 02b hand function).
  calc_model_summary_expansion_wave3_discovery_note(t.model_summary_id) AS expansion_wave3_discovery_note-- Expansion-wave-3 supersession-audit synthesis rollup (loop-78, promoted to native loop-90).
FROM model_summary t;

-- ----------------------------------------------------------------------------
-- vw_stratum_variables: Table: StratumVariables — one row per study, naming the variable that defines the strata and describing its causal role. A confounder affects both treatment assignment AND outcome; a mediator is downstream of treatment; a contested variable is one where the causal role is disputed. IsConfounder is derived from these two boolean flags.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stratum_variables CASCADE;
CREATE VIEW vw_stratum_variables WITH (security_invoker = ON) AS
SELECT
  t.stratum_variable_id,                                                        -- Unique slug (e.g. kidney-1986-stone-size).
  calc_stratum_variables_name(t.stratum_variable_id) AS name,                   -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.variable_name,                                                              -- The name of the stratifying variable (e.g. stone_size, department, age_group).
  t.causal_role,                                                                -- The variable's causal role: 'confounder' (affects both assignment and outcome), 'mediator' (downstream of treatment), 'contested' (causal role disputed), 'unknown'.
  t.affects_treatment_assignment,                                               -- TRUE if this variable causally influences which treatment a patient receives. Required for confounding.
  t.affects_outcome,                                                            -- TRUE if this variable causally influences the outcome independently of treatment. Required for confounding.
  calc_stratum_variables_is_confounder(t.stratum_variable_id) AS is_confounder, -- TRUE when AffectsTreatmentAssignment AND AffectsOutcome AND CausalRole = 'confounder'. A confounder is the classic driver of Simpson's Paradox.
  t.mechanism_note,                                                             -- Plain-language description of how this variable creates the confounding: why it affects both assignment and outcome.
  t.conditioning_risk,                                                          -- The causal hazard posed by conditioning on this variable. Values: confounder (safe to condition — removes bias), mediator (conditioning blocks the causal path of interest — harmful), collider (conditioning opens a spurious backdoor — harmful), proxy (conditioning on a noisy proxy of the true confounder — risky), none (no conditioning risk identified). NULL means unclassified.
  calc_stratum_variables_confounder_identity(t.stratum_variable_id) AS confounder_identity-- Canonical cross-study identity via StratumVariableIdentityMaps (loop-80).
FROM stratum_variables t;

-- ----------------------------------------------------------------------------
-- vw_treatment_rankings: Table: TreatmentRankings — one row per treatment-pair comparison within a study. Derives the pooled winner, the per-stratum winner, and the IsReversal boolean. The paradox emerges here as a derived fact: IsReversal is true when the pooled winner and the per-stratum winner disagree.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_treatment_rankings CASCADE;
CREATE VIEW vw_treatment_rankings WITH (security_invoker = ON) AS
SELECT
  t.treatment_ranking_id,                                                       -- Unique slug (e.g. kidney-1986-A-vs-B).
  calc_treatment_rankings_name(t.treatment_ranking_id) AS name,                 -- Display label.
  t.study,                                                                      -- FK to the parent Study.
  t.treatment_a,                                                                -- Label for the first treatment in the comparison (matches Treatments.TreatmentLabel).
  t.treatment_b,                                                                -- Label for the second treatment in the comparison.
  calc_treatment_rankings_total_cases_a(t.treatment_ranking_id) AS total_cases_a,-- Total cases for TreatmentA across all strata in this study.
  calc_treatment_rankings_total_successes_a(t.treatment_ranking_id) AS total_successes_a,-- Total successes for TreatmentA across all strata.
  calc_treatment_rankings_pooled_rate_a(t.treatment_ranking_id) AS pooled_rate_a,-- Pooled success rate for TreatmentA: TotalSuccessesA / TotalCasesA.
  calc_treatment_rankings_total_cases_b(t.treatment_ranking_id) AS total_cases_b,-- Total cases for TreatmentB across all strata.
  calc_treatment_rankings_total_successes_b(t.treatment_ranking_id) AS total_successes_b,-- Total successes for TreatmentB across all strata.
  calc_treatment_rankings_pooled_rate_b(t.treatment_ranking_id) AS pooled_rate_b,-- Pooled success rate for TreatmentB: TotalSuccessesB / TotalCasesB.
  calc_treatment_rankings_pooled_winner(t.treatment_ranking_id) AS pooled_winner,-- Which treatment wins when strata are ignored. Returns tie when pooled rates are equal within floating-point tolerance.
  calc_treatment_rankings_stratum_count(t.treatment_ranking_id) AS stratum_count,-- Number of strata in this study. Counted from StratumSummaries filtered to TreatmentA rows (one row per stratum).
  calc_treatment_rankings_strata_won_by_a(t.treatment_ranking_id) AS strata_won_by_a,-- Number of strata where A wins: count StratumSummaries rows whose TreatmentLabel=TreatmentA AND StratumWinner=TreatmentA. These are the one-per-stratum sentinel rows.
  calc_treatment_rankings_strata_won_by_b(t.treatment_ranking_id) AS strata_won_by_b,-- Number of strata where B wins: count StratumSummaries rows whose TreatmentLabel=TreatmentA AND StratumWinner=TreatmentB.
  calc_treatment_rankings_per_stratum_winner(t.treatment_ranking_id) AS per_stratum_winner,-- The treatment that wins in every stratum — 'A' if StrataWonByA = StratumCount, 'B' if StrataWonByB = StratumCount, else 'none' (no unanimous per-stratum winner).
  calc_treatment_rankings_is_stratum_unanimous(t.treatment_ranking_id) AS is_stratum_unanimous,-- TRUE when one treatment wins every stratum (StrataWonByA = StratumCount OR StrataWonByB = StratumCount). Maps A/B policy split: unanimous → stratify-immediately geometry; heterogeneous → investigate-confounder.
  calc_treatment_rankings_is_reversal(t.treatment_ranking_id) AS is_reversal,   -- TRUE when the equal-weight pooled signal (WeightedStratumGapSum) and the actual pooled signal (SignedPooledGap) point in opposite directions — allocation has flipped the direction of the aggregate conclusion. This is Simpson's Paradox as a derived fact.
  calc_treatment_rankings_confounders_in_study(t.treatment_ranking_id) AS confounders_in_study,-- Count of StratumVariables in this study whose IsConfounder = TRUE. When > 0, the paradox has a causal explanation.
  calc_treatment_rankings_is_paradox_explained(t.treatment_ranking_id) AS is_paradox_explained,-- TRUE when IsReversal is present AND at least one confirmed confounder exists in the study.
  calc_treatment_rankings_pooled_gap(t.treatment_ranking_id) AS pooled_gap,     -- Absolute difference between the two pooled rates: |PooledRateA - PooledRateB|. The size of the aggregate misleading signal.
  calc_treatment_rankings_strata_won_by_loser(t.treatment_ranking_id) AS strata_won_by_loser,-- Number of strata won by the pooled loser — the counter-signal. For full reversals this equals StratumCount; for partial paradoxes it is between 0 and StratumCount.
  calc_treatment_rankings_paradox_strength(t.treatment_ranking_id) AS paradox_strength,-- Scalar severity of the paradox: PooledGap × (StrataWonByLoser / StratumCount). Zero when no strata go against the pooled winner. Positive for partial paradoxes. Maximum when every stratum contradicts the pooled result.
  calc_treatment_rankings_pooled_rate_from_weights_a(t.treatment_ranking_id) AS pooled_rate_from_weights_a,-- Pooled rate for TreatmentA reconstructed as a weighted average of stratum rates: SUM(WeightedStratumRate) across all stratum rows for TreatmentA. Must match PooledRateA — this witnesses the mechanism equation: the pooled rate IS a weighted average of stratum rates, weighted by StratumFraction.
  calc_treatment_rankings_pooled_rate_from_weights_b(t.treatment_ranking_id) AS pooled_rate_from_weights_b,-- Pooled rate for TreatmentB reconstructed as a weighted average. Must match PooledRateB. If it does, the mechanism equation is verified: reversal is purely a consequence of differential weighting.
  calc_treatment_rankings_reversal_intensity(t.treatment_ranking_id) AS reversal_intensity,-- StrataWonByLoser / StratumCount: the fraction of strata that go against the pooled winner. Zero for no paradox, 1.0 for full reversal, between 0 and 1 for partial. This is the allocation-side measure of how deeply the confounding has penetrated the stratified view.
  calc_treatment_rankings_threshold_margin(t.treatment_ranking_id) AS threshold_margin,-- ReversalIntensity minus 0.5: positive when more than half the strata go against the pooled winner (reversal is robust), zero at the tipping point (exactly half), negative when fewer than half oppose the pooled winner (reversal is fragile or absent). A study with ThresholdMargin > 0 is robustly paradoxical; one with ThresholdMargin < 0 has a weak or absent paradox.
  calc_treatment_rankings_signed_pooled_gap(t.treatment_ranking_id) AS signed_pooled_gap,-- Signed difference between pooled rates: PooledRateA minus PooledRateB. Positive = A wins pooled; negative = B wins pooled. Unlike PooledGap (which is absolute), this preserves direction — essential for detecting sign flips between the equal-weight and actual pooled signals.
  calc_treatment_rankings_weighted_stratum_gap_sum(t.treatment_ranking_id) AS weighted_stratum_gap_sum,-- Sum of WeightedStratumGap (= StratumGap × StratumFraction) across all StratumSummaries rows where TreatmentLabel = TreatmentA for this study. This is the equal-weight pooled gap — the gap the pooled analysis would produce if allocation were perfectly balanced across strata. When this has the opposite sign to SignedPooledGap, the allocation has not merely compressed the signal: it has flipped it entirely.
  calc_treatment_rankings_is_sign_flip(t.treatment_ranking_id) AS is_sign_flip, -- TRUE when WeightedStratumGapSum and SignedPooledGap have opposite signs. Same condition as IsReversal; retained as the coordinate-level name in the DAG.
  calc_treatment_rankings_allocation_distortion(t.treatment_ranking_id) AS allocation_distortion,-- The magnitude of how far the allocation has bent the pooled signal: |WeightedStratumGapSum − SignedPooledGap|. Zero means the allocation is neutral — the pooled analysis faithfully represents the equal-weight stratum evidence. A large AllocationDistortion means the allocation is doing most of the work: the pooled number is mostly noise from how cases were assigned, not signal about which treatment is better. This measure does NOT require a sign flip to be nonzero — it captures any allocation-induced distortion, not just reversals.
  calc_treatment_rankings_distortion_type(t.treatment_ranking_id) AS distortion_type,-- Geometric classification (five types A/B/C+/C-/D). Sign-flip types: A = unanimous stratum direction (IsStratumUnanimous); B = heterogeneous stratum directions. Non-flip: C+/C-/D by distortion ratio.
  calc_treatment_rankings_policy_implication(t.treatment_ranking_id) AS policy_implication,-- The researcher action implied by the geometric classification. Derived from DistortionType: type A (full reversal) → 'stratify-immediately' — the pooled conclusion is directionally wrong; do not act on it without stratifying. Type B (partial sign-flip) → 'investigate-confounder' — the equal-weight signal opposes the pooled signal, but the per-stratum picture is mixed; the causal mechanism needs examination before trusting either estimate. Type C (compression without flip) → 'check-allocation-bias' — the pooled winner is probably correct but the effect size is distorted; report adjusted or standardized margins rather than the raw pooled gap. Type D (neutral) → 'pooled-analysis-trustworthy' — allocation is not materially distorting the signal; the pooled conclusion is safe with respect to this stratification.
  calc_treatment_rankings_corrected_gap(t.treatment_ranking_id) AS corrected_gap,-- The allocation-corrected treatment gap: WeightedStratumGapSum, i.e. what SignedPooledGap would be if allocation were equal across strata. Positive means A is favoured in the corrected world; negative means B is favoured.
  calc_treatment_rankings_corrected_winner(t.treatment_ranking_id) AS corrected_winner,-- Which treatment wins once allocation bias is removed. Derived from CorrectedGap: positive → TreatmentA; negative → TreatmentB; near-zero → tie.
  calc_treatment_rankings_corrected_vs_pooled_agreement(t.treatment_ranking_id) AS corrected_vs_pooled_agreement,-- TRUE when the allocation-corrected winner matches the pooled winner. FALSE when removing allocation bias would change which treatment appears to win — the machine-readable definition of a reversal recovery.
  calc_treatment_rankings_corrected_policy_implication(t.treatment_ranking_id) AS corrected_policy_implication,-- The allocation-aware researcher action: what to do when the corrected verdict is available. Derived from DistortionType and CorrectedWinner together, making the instrument self-consistent with Reversal Recovery (loop-27). Type A (full sign-flip, unanimous per-stratum reversal): CorrectedWinner is the true signal — 'use-corrected-winner'. The pooled analysis was directionally wrong; act on CorrectedWinner, not PooledWinner. Type B (partial sign-flip, non-unanimous): CorrectedWinner points against the pooled signal but strata disagree among themselves — 'use-corrected-winner-with-caution'. Trust the corrected direction but acknowledge residual uncertainty. Type C (compression, no sign flip): PooledWinner is directionally correct; the distortion is in the magnitude, not the direction — 'check-allocation-bias'. Same as PolicyImplication. Type D (neutral): allocation is not materially distorting the signal — 'pooled-analysis-trustworthy'. Same as PolicyImplication. For Types C and D, CorrectedPolicyImplication and PolicyImplication always agree; for Types A and B, CorrectedPolicyImplication supersedes PolicyImplication with the allocation-corrected verdict.
  calc_treatment_rankings_allocation_direction(t.treatment_ranking_id) AS allocation_direction,-- Whether the allocation is reversing, amplifying, or compressing the true treatment signal (CorrectedGap). 'reversal': allocation changed the sign of the pooled gap relative to CorrectedGap — worst case; pooled winner is wrong (types A and B). 'amplification': allocation inflated the pooled gap beyond CorrectedGap in the same direction — pooled winner is correct but effect size is overstated (type C+). 'compression': allocation shrank the pooled gap below CorrectedGap in the same direction — pooled winner is correct but effect size is understated (type C-). 'neutral': allocation had negligible effect on the pooled gap (type D). Policy consequences: reversal → wrong decision; amplification → overconfidence; compression → underconfidence / premature abandonment; neutral → trustworthy.
  calc_treatment_rankings_signal_purity(t.treatment_ranking_id) AS signal_purity,-- The fraction of total observed variation (|CorrectedGap| + AllocationDistortion) that is genuine treatment signal rather than allocation noise. SignalPurity = |CorrectedGap| / (|CorrectedGap| + AllocationDistortion). Range [0,1]: 1.0 = allocation contributed nothing (type D); 0 = corrected gap is zero (pure noise). Critical threshold is 0.5: SignalPurity < 0.5 means allocation noise exceeds true signal. The signal-purity theorem (loop-44): AllocationDirection='reversal' → SignalPurity < 0.5. Equivalently: a sign flip requires the confound to produce more distortion than the treatment produced signal. This is the mechanistic account of why reversals happen: not study-design accidents but algebraic necessities.
  calc_treatment_rankings_pooled_gap_crosses_zero(t.treatment_ranking_id) AS pooled_gap_crosses_zero,-- Lookup: SweepStudySummary.PooledGapCrossesZero via Study. TRUE when reweighting allocation would change the sign of the pooled gap.
  calc_treatment_rankings_sweep_pooled_gap_range(t.treatment_ranking_id) AS sweep_pooled_gap_range,-- Lookup: SweepStudySummary.SweepPooledGapRange via Study. Width of pooled-gap wander under allocation sweep.
  calc_treatment_rankings_latent_flip_potential(t.treatment_ranking_id) AS latent_flip_potential,-- TRUE when DistortionType=D but PooledGapCrossesZero=TRUE — SAFE at observed allocation but flip-capable under counterfactual reweighting.
  calc_treatment_rankings_allocation_fragility(t.treatment_ranking_id) AS allocation_fragility,-- SweepPooledGapRange divided by |PooledGap|. High values mean small observed effect but wide counterfactual wander. Fixed loop-90: this rulebook's IF(x="","",...) blank-on-degenerate idiom transpiles to a bare ''::numeric cast that errors at runtime the moment a live row genuinely has PooledGap=0 (surfaced only once _erb_tr_metrics, which masked this row, was eliminated). Returns 0 for the degenerate case instead — see TreatmentRankings.DistortionRatio for the same fix pattern.
  calc_treatment_rankings_max_stratum_imbalance(t.treatment_ranking_id) AS max_stratum_imbalance,-- MAXIFS(StratumSummaries.AbsAllocationBias) over rows where Study matches and TreatmentLabel='A' — the largest allocation-share skew any single stratum shows for this study. Live aggregation; replaces the former hand-written _erb_tr_metrics cache column of the same name.
  calc_treatment_rankings_max_stratum_gap(t.treatment_ranking_id) AS max_stratum_gap,-- MAXIFS(StratumSummaries.AbsStratumGap) over rows where Study matches and TreatmentLabel='A' — the largest within-stratum rate gap for this study. Live aggregation; replaces the former hand-written _erb_tr_metrics cache column of the same name.
  calc_treatment_rankings_is_sweep_fragile(t.treatment_ranking_id) AS is_sweep_fragile,-- Type-D study that is pooled-safe but ultra-fragile under allocation reweighting: signal_purity=1, allocation_distortion=0, sweep_pooled_gap_range>0.3, allocation_fragility>=10.
  calc_treatment_rankings_study_domain(t.treatment_ranking_id) AS study_domain, -- Lookup: Studies.Domain via Study.
  calc_treatment_rankings_stratum_causal_role(t.treatment_ranking_id) AS stratum_causal_role,-- Lookup: StratumVariables.CausalRole for this study — confounder, mediator, collider, selection, contested, etc.
  calc_treatment_rankings_is_latent_only_flip(t.treatment_ranking_id) AS is_latent_only_flip,-- TRUE when allocation sweep crosses zero but observed allocation shows no sign flip — latent-only reversal.
  calc_treatment_rankings_confirmed_causal_role_count(t.treatment_ranking_id) AS confirmed_causal_role_count,-- Count of StratumVariables in this study whose CausalRole is "confounder" — includes variables that confound the outcome regardless of whether allocation was balanced.
  calc_treatment_rankings_mediator_risk_count(t.treatment_ranking_id) AS mediator_risk_count,-- Count of StratumVariables in this study whose ConditioningRisk is mediator or collider — the hazardous conditioning types.
  calc_treatment_rankings_contested_stratum_count(t.treatment_ranking_id) AS contested_stratum_count,-- Count of StratumVariables in this study whose CausalRole is contested — the causal interpretation is disputed.
  calc_treatment_rankings_unknown_causal_role_count(t.treatment_ranking_id) AS unknown_causal_role_count,-- Count of StratumVariables in this study whose CausalRole is unknown — no causal account has been established.
  calc_treatment_rankings_causal_claim_status(t.treatment_ranking_id) AS causal_claim_status,-- The epistemic status of the causal interpretation for this study. Values: established (all stratum variables are confirmed confounders with known mechanisms), contested (at least one stratum variable has a disputed causal role — e.g. Berkeley 1973 where department choice may be endogenous), geometric-only (no stratum variable has an established causal role — the distortion is a geometric fact, not a causal claim). Derived from StratumVariables.CausalRole and ConditioningRisk.
  calc_treatment_rankings_adjustment_appropriate(t.treatment_ranking_id) AS adjustment_appropriate,-- TRUE only when it is epistemically safe to act on CorrectedGap as the causal treatment effect estimate: no mediator/collider conditioning risk AND causal claim is established (not contested or geometric-only). FALSE for the birth-weight paradox (mediator), berkeley-1973 (contested), and synthetic/degenerate studies (geometric-only).
  t.adjustment_rationale,                                                       -- Human-authored note explaining why AdjustmentAppropriate is TRUE or FALSE for this study. Covers mediator/collider hazards, contested causal roles, and cases where geometric correction is valid but causal interpretation is uncertain.
  calc_treatment_rankings_purity_trap_flag(t.treatment_ranking_id) AS purity_trap_flag,-- TRUE when SignalPurity >= 0.90 AND the study's confounder identity has PolicyDefault IN ('do-not-condition','do-not-naively-adjust'). Marks the purity trap: data appears cleanest where naive stratification is most harmful.
  calc_treatment_rankings_distortion_ratio(t.treatment_ranking_id) AS distortion_ratio,-- SignedPooledGap / WeightedStratumGapSum. Promoted loop-90 from a 03b-customize-views.sql presentation-layer bolt-on to a first-class rulebook field. The IF(x=0,"",...) blank-on-zero-denominator idiom used elsewhere in this rulebook is unsafe here: NULLIF is not a supported transpiler function, and the transpiler's translation of the "" branch for a numeric-typed field is a bare ''::numeric cast that errors at runtime the moment a live row actually hits it (4 of 242 TreatmentRankings rows have WeightedStratumGapSum=0). Returns 0 in that case instead — WeightedStratumGapSum=0 means there is no equal-weight baseline signal to compare against, so a 0 ratio (no distortion multiplier) is the defensible convention, not a guess.
  calc_treatment_rankings_screening_tier(t.treatment_ranking_id) AS screening_tier,-- DANGER when DistortionType is A or B, CAUTION when C+/C-, SAFE when D. Promoted loop-90 (see DistortionRatio).
  calc_treatment_rankings_arm_size_ratio(t.treatment_ranking_id) AS arm_size_ratio,-- TotalCasesA / (TotalCasesA + TotalCasesB) — the share of total cases allocated to TreatmentA. Promoted loop-90 (see DistortionRatio for why the empty-string zero-denominator idiom is unsafe on a numeric field). Returns 0 for the degenerate zero-case-count edge (never occurs in this corpus, kept for defensive symmetry with DistortionRatio).
  calc_treatment_rankings_symmetry_departure(t.treatment_ranking_id) AS symmetry_departure-- ABS(ArmSizeRatio - 0.5) — how far the case allocation departs from a balanced 50/50 split. Promoted loop-90 (see DistortionRatio).
FROM treatment_rankings t;

-- ----------------------------------------------------------------------------
-- vw_invariant_checks: Table: InvariantChecks — one row per algebraic invariant across the 40-study validation corpus. PassCount and FailCount are populated by run_invariant_checks() in 05b-customize-data.sql. Any critical FailCount > 0 breaks the build.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_invariant_checks CASCADE;
CREATE VIEW vw_invariant_checks WITH (security_invoker = ON) AS
SELECT
  t.invariant_check_id,                                                         -- Unique slug for this invariant (e.g. inv-balanced-alloc).
  calc_invariant_checks_name(t.invariant_check_id) AS name,                     -- Display label.
  t.algebraic_statement,                                                        -- The mathematical assertion in compact symbolic form.
  t.natural_language,                                                           -- Plain-English statement of what property must hold and why it is an invariant of the model.
  t.source_table,                                                               -- The DAG table whose rows are checked (TreatmentRankings or StratumSummaries).
  t.filter_expression,                                                          -- Condition selecting the universe of rows this invariant applies to. Empty means all rows.
  t.assertion_expression,                                                       -- The per-row condition that must be TRUE for every row in scope.
  t.sql_filter,                                                                 -- Optional SQL WHERE clause that selects the universe of rows in scope for this invariant (e.g. distortion_type = 'D'). Empty string means all rows.
  t.sql_assertion,                                                              -- The SQL WHERE clause (without WHERE keyword) that counts PASSING rows from vw_treatment_rankings for this invariant. Used by run_invariant_checks() to evaluate each assertion dynamically from the rulebook table.
  t.pass_count,                                                                 -- Rows where the invariant holds. Populated by 05b-customize-data.sql from a live query against vw_treatment_rankings.
  t.fail_count,                                                                 -- Rows where the invariant is violated. Any FailCount > 0 is a build-breaking bug.
  calc_invariant_checks_universe_count(t.invariant_check_id) AS universe_count, -- Total rows in scope (PassCount + FailCount).
  calc_invariant_checks_is_green(t.invariant_check_id) AS is_green,             -- TRUE when FailCount = 0.
  calc_invariant_checks_status_label(t.invariant_check_id) AS status_label,     -- PASS or FAIL(n) summary for display.
  t.severity,                                                                   -- critical | warning — critical means any FailCount > 0 is a build-breaking bug.
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The tradition whose theoretical commitments this algebraic invariant protects — a failed invariant would falsify that tradition's key claim.
  t.protects_conclusion,                                                        -- FK → Conclusions.ConclusionId. The conclusion whose witness depends on this invariant holding. If this invariant fails, that conclusion is undermined.
  calc_invariant_checks_tradition_name(t.invariant_check_id) AS tradition_name, -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_invariant_checks_tradition_key_claim_summary(t.invariant_check_id) AS tradition_key_claim_summary,-- Lookup: ResearchTraditions.KeyClaim via TraditionId — a failed invariant would falsify this tradition's key claim.
  calc_invariant_checks_protects_conclusion_title(t.invariant_check_id) AS protects_conclusion_title,-- Lookup: Conclusions.Title via ProtectsConclusion.
  calc_invariant_checks_protects_conclusion_category(t.invariant_check_id) AS protects_conclusion_category-- Lookup: Conclusions.Category via ProtectsConclusion.
FROM invariant_checks t;

-- ----------------------------------------------------------------------------
-- vw_materialized_entities: Table: MaterializedEntities — governance record of every entity in this rulebook whose fields are principled materializations rather than live-calculated (per project CLAUDE.md: allowed only when the computation is genuinely expensive AND its upstream is sealed/stable, expressed as data in the rulebook itself, never as an ad-hoc application cache). Each row names the entity, the refresh contract, the refresh function that implements it, and the measured cost that justified materializing it. If this table's row for an entity were deleted, the entity's fields should still be regeneratable identically from the SSoT + the refresh function — that is the test for whether a materialization here is principled.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_materialized_entities CASCADE;
CREATE VIEW vw_materialized_entities WITH (security_invoker = ON) AS
SELECT
  t.materialized_entity_id,                                                     -- Unique slug (e.g. mat-sweep-study-summary).
  calc_materialized_entities_name(t.materialized_entity_id) AS name,            -- Display label, mirrors MaterializedEntityId.
  t.entity_table,                                                               -- The rulebook table whose fields are materialized (e.g. SweepStudySummary).
  t.refresh_contract,                                                           -- eager-on-write | on-demand | scheduled — when the refresh function is invoked relative to writes on the upstream data.
  t.refresh_function,                                                           -- The SQL function (in the customize-* override files) that recomputes this entity's materialized fields from its upstream SSoT tables.
  t.upstream_tables,                                                            -- Comma-separated list of the tables this materialization is derived from — its sealed/stable upstream.
  t.justification                                                               -- The measured cost or evidence that justified materializing this entity instead of leaving it as a live calculated/aggregation field.
FROM materialized_entities t;

-- ----------------------------------------------------------------------------
-- vw_methodology: Table: Methodology — the first-principles process used to build this domain model. Each row documents one methodological axiom or step. Together these rows let a reader (or an LLM) reconstruct why the model is shaped the way it is, and re-apply the same process to a new domain.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_methodology CASCADE;
CREATE VIEW vw_methodology WITH (security_invoker = ON) AS
SELECT
  t.methodology_id,                                                             -- Unique slug (e.g. method-01-cmcc, method-02-dag-first).
  calc_methodology_name(t.methodology_id) AS name,                              -- Display label, mirrors MethodologyId.
  t.phase,                                                                      -- Broad phase: axiom | decomposition | derivation | hydration | validation | taxonomy | conclusion
  t.title,                                                                      -- Short title of the methodological principle or step.
  t.statement,                                                                  -- One-to-three sentence statement of the principle, precise enough to be applied or falsified.
  t.why_it_matters,                                                             -- Why this step or principle is load-bearing for this model — what breaks if you skip it.
  t.illustrated_by_loop,                                                        -- LoopId(s) where this principle was concretely demonstrated (comma-separated).
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The scholarly tradition that introduced or most relies on this methodological approach.
  t.pioneering_researcher,                                                      -- FK → Researchers.ResearcherId. The researcher most associated with developing or popularising this methodological principle in the Simpson's Paradox context.
  calc_methodology_tradition_name(t.methodology_id) AS tradition_name,          -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_methodology_tradition_primary_venue(t.methodology_id) AS tradition_primary_venue,-- Lookup: ResearchTraditions.PrimaryVenue via TraditionId.
  calc_methodology_pioneering_researcher_name(t.methodology_id) AS pioneering_researcher_name,-- Lookup: Researchers.Name via PioneeringResearcher.
  calc_methodology_pioneering_researcher_affiliation(t.methodology_id) AS pioneering_researcher_affiliation,-- Lookup: Researchers.Affiliation via PioneeringResearcher.
  calc_methodology_loop_count(t.methodology_id) AS loop_count                   -- Count of Loops whose TraditionId matches this methodology entry's TraditionId — how many build iterations this methodological tradition has driven.
FROM methodology t;

-- ----------------------------------------------------------------------------
-- vw_conclusions: Table: Conclusions — the substantive epistemic findings that this model has produced or is designed to produce. Each row is one conclusion: a claim about the domain, about the instrument, or about the methodology that is either already witnessed or is the target of a planned loop.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_conclusions CASCADE;
CREATE VIEW vw_conclusions WITH (security_invoker = ON) AS
SELECT
  t.conclusion_id,                                                              -- Unique slug (e.g. conc-01-paradox-is-derived).
  calc_conclusions_name(t.conclusion_id) AS name,                               -- Display label, mirrors ConclusionId.
  t.category,                                                                   -- domain | instrument | methodology | open-question | corpus-theorem
  t.status,                                                                     -- witnessed | planned | open
  t.report_tier,                                                                -- critical | supporting | transient — controls how much space this conclusion gets in the generated PDF/summary report. critical = full section with evidence + chart; supporting = 1-2 line bullet; transient = folded into a single compact list.
  t.validating_hypothesis,                                                      -- FK → DiscoveryHypotheses.HypothesisId. The pre-registered hypothesis whose live DiscoveryFindings.IsConfirmed value is the current-truth check for this conclusion — set on theorem/corpus-theorem conclusions so a report can distinguish a conclusion's archived prose (may say 'Proved') from its live status (may since be contradicted by corpus growth). Null when no single hypothesis tests this exact claim.
  calc_conclusions_live_status_confirmed(t.conclusion_id) AS live_status_confirmed,-- Lookup: DiscoveryFindings.IsConfirmed via ValidatingHypothesis — the current pass/fail state of the hypothesis backing this conclusion, recomputed on every build from live corpus data. NULL when ValidatingHypothesis is not set (no live check exists for this conclusion).
  calc_conclusions_live_status_observed_metric(t.conclusion_id) AS live_status_observed_metric,-- Lookup: DiscoveryFindings.ObservedMetric via ValidatingHypothesis — the current observed values for the hypothesis backing this conclusion, so a reader can see exactly why it currently passes or fails.
  t.title,                                                                      -- One-line statement of the conclusion.
  t.evidence,                                                                   -- The specific DB query result, loop outcome, or argument that establishes or will establish this conclusion.
  t.witnessed_in_loop,                                                          -- LoopId where this conclusion was first witnessed (if status=witnessed).
  t.target_loop,                                                                -- LoopId that is designed to witness this conclusion (if status=planned).
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The tradition whose theoretical framework this conclusion primarily vindicates, refines, or challenges.
  t.researcher_id,                                                              -- FK → Researchers.ResearcherId. The researcher whose specific claim, definition, or framework this conclusion directly affirms.
  t.challenges_researcher,                                                      -- FK → Researchers.ResearcherId. A researcher whose position this conclusion refutes or qualifies (e.g. conc-03 refutes Blyth's unanimity criterion as the primary definition).
  calc_conclusions_tradition_name(t.conclusion_id) AS tradition_name,           -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_conclusions_tradition_key_claim_summary(t.conclusion_id) AS tradition_key_claim_summary,-- Lookup: ResearchTraditions.KeyClaim via TraditionId — shows which tradition's central claim this conclusion validates or refines.
  calc_conclusions_researcher_name(t.conclusion_id) AS researcher_name,         -- Lookup: Researchers.Name via ResearcherId.
  calc_conclusions_researcher_affiliation(t.conclusion_id) AS researcher_affiliation,-- Lookup: Researchers.Affiliation via ResearcherId.
  calc_conclusions_challenges_researcher_name(t.conclusion_id) AS challenges_researcher_name,-- Lookup: Researchers.Name via ChallengesResearcher.
  calc_conclusions_witnessed_in_loop_title(t.conclusion_id) AS witnessed_in_loop_title,-- Lookup: Loops.Title via WitnessedInLoop.
  calc_conclusions_witnessed_in_loop_commit_hash(t.conclusion_id) AS witnessed_in_loop_commit_hash,-- Lookup: Loops.CommitHash via WitnessedInLoop — git checkout this SHA to replay the instrument state when this conclusion was first witnessed.
  calc_conclusions_witnessed_in_loop_commit_short(t.conclusion_id) AS witnessed_in_loop_commit_short,-- Lookup: Loops.CommitShort via WitnessedInLoop.
  calc_conclusions_witnessed_in_loop_commit_date(t.conclusion_id) AS witnessed_in_loop_commit_date,-- Lookup: Loops.CommitDate via WitnessedInLoop.
  calc_conclusions_witnessed_in_loop_git_tag(t.conclusion_id) AS witnessed_in_loop_git_tag,-- Lookup: Loops.GitTag via WitnessedInLoop — preferred replay entry point when a milestone tag exists.
  calc_conclusions_invariant_protecting_count(t.conclusion_id) AS invariant_protecting_count-- Count of InvariantChecks whose ProtectsConclusion FK points to this conclusion — how many algebraic invariants stand behind this finding.
FROM conclusions t;

-- ----------------------------------------------------------------------------
-- vw_ui_screens: Table: UIScreens — the canonical screens that comprise the Simpson's Paradox Explorer UI. Each row defines one screen: its purpose, its primary data source (which rulebook view it reads), and the user action it supports. A developer can reconstruct the full UI from this table without any prior knowledge of the application.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ui_screens CASCADE;
CREATE VIEW vw_ui_screens WITH (security_invoker = ON) AS
SELECT
  t.screen_id,                                                                  -- Unique slug (e.g. screen-01-study-list).
  calc_ui_screens_name(t.screen_id) AS name,                                    -- Display label, mirrors ScreenId.
  t.title,                                                                      -- Human-readable screen title shown in the UI.
  t.route,                                                                      -- URL path pattern (e.g. /, /study/:studyId, /compare).
  t.primary_entity,                                                             -- The main rulebook entity this screen reads from (the vw_* view name without prefix).
  t.purpose,                                                                    -- One sentence: what a user can learn or do on this screen.
  t.key_fields,                                                                 -- Comma-separated list of the most important fields displayed on this screen.
  t.user_action,                                                                -- Primary user action available on this screen (e.g. select a study, drill into a stratum).
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId. The scholarly tradition whose lens this screen primarily serves — determines which framing language and which fields are most prominent.
  t.primary_conclusion,                                                         -- FK → Conclusions.ConclusionId. The conclusion this screen most directly visualises or communicates to the user.
  calc_ui_screens_tradition_name(t.screen_id) AS tradition_name,                -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_ui_screens_tradition_core_conern(t.screen_id) AS tradition_core_conern,  -- Lookup: ResearchTraditions.CoreConcern via TraditionId — the lens this screen applies.
  calc_ui_screens_primary_conclusion_title(t.screen_id) AS primary_conclusion_title,-- Lookup: Conclusions.Title via PrimaryConclusion.
  calc_ui_screens_primary_conclusion_evidence(t.screen_id) AS primary_conclusion_evidence-- Lookup: Conclusions.Evidence via PrimaryConclusion.
FROM ui_screens t;

-- ----------------------------------------------------------------------------
-- vw_ui_components: Table: UIComponents — the reusable visual building blocks used across UIScreens. Each row defines one component: what it renders, which entity it reads, and what props it requires. A developer can implement the full UI by composing these components onto the screens defined in UIScreens.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ui_components CASCADE;
CREATE VIEW vw_ui_components WITH (security_invoker = ON) AS
SELECT
  t.component_id,                                                               -- Unique slug (e.g. comp-01-distortion-badge).
  calc_ui_components_name(t.component_id) AS name,                              -- Display label, mirrors ComponentId.
  t.component_name,                                                             -- Code-level component name (PascalCase, e.g. DistortionBadge).
  t.used_on_screens,                                                            -- Comma-separated ScreenIds where this component appears.
  t.primary_entity,                                                             -- The rulebook entity this component reads (the vw_* view).
  t.description,                                                                -- What this component renders and what decisions a developer must make to implement it.
  t.required_fields,                                                            -- Comma-separated rulebook fields this component must receive as props.
  t.visual_spec                                                                 -- Plain-English description of the visual output: shape, color coding, interactivity.
FROM ui_components t;

-- ----------------------------------------------------------------------------
-- vw_instrument_spec: Table: InstrumentSpec — the complete specification of the Simpson's Paradox classification instrument. One row per component: required input fields, derived coordinates, classification outputs, and adapter requirements. Every row is machine-verifiable against the 238-study corpus. This table is the distillation of loops 1–25 into a reusable tool.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_instrument_spec CASCADE;
CREATE VIEW vw_instrument_spec WITH (security_invoker = ON) AS
SELECT
  t.spec_id,                                                                    -- Unique identifier for this instrument component.
  calc_instrument_spec_name(t.spec_id) AS name,                                 -- Display label.
  t.component_type,                                                             -- input | derived | classification | adapter-requirement
  t.field_name,                                                                 -- The field or variable name in the DAG.
  t.data_type,                                                                  -- integer | decimal | boolean | string | categorical
  t.source_table,                                                               -- The DAG table where this field is computed or stored.
  t.formula,                                                                    -- The ERB formula or derivation rule for this component.
  t.natural_language,                                                           -- Plain-English statement of what this component represents or requires.
  t.adapter_note                                                                -- What a researcher must supply or verify to satisfy this component when hydrating a new study.
FROM instrument_spec t;

-- ----------------------------------------------------------------------------
-- vw_allocation_sweep: Table: AllocationSweep — parametric sweep of treatment-A allocation fraction within each study's most confounded stratum (see SweepStudyConfig). Ten fractions from 0.05 to 0.95 per study. SweepCorrectedGap is invariant; SweepPooledGap wanders.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_allocation_sweep CASCADE;
CREATE VIEW vw_allocation_sweep WITH (security_invoker = ON) AS
SELECT
  t.sweep_id,                                                                   -- Unique row identifier: <study>-f<pct> where pct is AllocFractionA*100.
  calc_allocation_sweep_name(t.sweep_id) AS name,                               -- Display label.
  t.study_id,                                                                   -- The study being swept — all 238 studies in the corpus.
  t.alloc_fraction_a,                                                           -- Fraction of the sweep-stratum cases assigned to treatment A. Ranges from 0.05 to 0.95. The sweep stratum is the one whose allocation was most confounded in the original study.
  calc_allocation_sweep_is_original(t.sweep_id) AS is_original,                 -- TRUE for the row closest to the actual original study allocation.
  calc_allocation_sweep_n_sweep_stratum_total(t.sweep_id) AS n_sweep_stratum_total,-- Total cases in the sweep stratum (the stratum whose allocation is being varied). Fixed per study.
  calc_allocation_sweep_n_sweep_a(t.sweep_id) AS n_sweep_a,                     -- Cases in the sweep stratum assigned to treatment A = ROUND(NSweepStratumTotal * AllocFractionA).
  calc_allocation_sweep_n_sweep_b(t.sweep_id) AS n_sweep_b,                     -- Cases in the sweep stratum assigned to treatment B = NSweepStratumTotal - NSweepA.
  calc_allocation_sweep_n_fixed_a(t.sweep_id) AS n_fixed_a,                     -- Total A-treatment cases in all NON-swept strata (held fixed across sweep rows). For kidney-1986 = 87 (small-stratum A). For berkeley-1973 = 1302 (depts B+C+D male). For compressed-synthetic = 80 (easy-stratum A). For balanced-synthetic = 100 (hard-stratum A).
  calc_allocation_sweep_n_fixed_b(t.sweep_id) AS n_fixed_b,                     -- Total B-treatment cases in all NON-swept strata (held fixed across sweep rows). For kidney-1986 = 270 (small-stratum B). For berkeley-1973 = 993 (depts B+C+D female). For compressed-synthetic = 120 (easy-stratum B). For balanced-synthetic = 100 (hard-stratum B).
  calc_allocation_sweep_sweep_rate_a(t.sweep_id) AS sweep_rate_a,               -- Per-cell success rate for treatment A in the sweep stratum. Fixed per study.
  calc_allocation_sweep_sweep_rate_b(t.sweep_id) AS sweep_rate_b,               -- Per-cell success rate for treatment B in the sweep stratum. Fixed per study.
  calc_allocation_sweep_fixed_rate_a(t.sweep_id) AS fixed_rate_a,               -- Weighted success rate for treatment A across all fixed (non-swept) strata. Constant per study.
  calc_allocation_sweep_fixed_rate_b(t.sweep_id) AS fixed_rate_b,               -- Weighted success rate for treatment B across all fixed (non-swept) strata. Constant per study.
  calc_allocation_sweep_sweep_pooled_rate_a(t.sweep_id) AS sweep_pooled_rate_a, -- Pooled success rate for treatment A = (NSweepA * SweepRateA + NFixedA * FixedRateA) / (NSweepA + NFixedA). Changes as AllocFractionA varies.
  calc_allocation_sweep_sweep_pooled_rate_b(t.sweep_id) AS sweep_pooled_rate_b, -- Pooled success rate for treatment B = (NSweepB * SweepRateB + NFixedB * FixedRateB) / (NSweepB + NFixedB). Changes as AllocFractionA varies.
  calc_allocation_sweep_sweep_pooled_gap(t.sweep_id) AS sweep_pooled_gap,       -- SweepPooledRateA minus SweepPooledRateB. Wanders as AllocFractionA varies because pooled rates mix stratum sizes unequally. Crosses zero at some allocation (the paradox reversal point).
  calc_allocation_sweep_sweep_corrected_gap(t.sweep_id) AS sweep_corrected_gap, -- Allocation-free signal: sum over strata of (n_s/N) * (rate_As - rate_Bs). Constant across the sweep by construction — the allocation variable does not appear. This is the conserved quantity under re-stratification.
  calc_allocation_sweep_allocation_distortion_witness(t.sweep_id) AS allocation_distortion_witness-- SweepPooledGap minus SweepCorrectedGap. The allocation distortion: how much the pooled signal has been inflated or deflated by differential stratum allocation. Zero only when allocation is balanced.
FROM allocation_sweep t;

-- ----------------------------------------------------------------------------
-- vw_sweep_study_summary: View for SweepStudySummary
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_sweep_study_summary CASCADE;
CREATE VIEW vw_sweep_study_summary WITH (security_invoker = ON) AS
SELECT
  t.sweep_study_id,                                                             -- FK to Studies.StudyId. One row per study in the AllocationSweep.
  calc_sweep_study_summary_name(t.sweep_study_id) AS name,                      -- Display label.
  calc_sweep_study_summary_distortion_type_label(t.sweep_study_id) AS distortion_type_label,-- DistortionType for this study (A, B, C, or D) — provides context for what the sweep should show.
  t.corrected_gap_constant,                                                     -- Principled materialization (refresh_sweep_study_summary(), 03b/05b customize SQL). The allocation-free corrected gap for this study = MINIFS(AllocationSweep[SweepCorrectedGap], AllocationSweep[StudyId], SweepStudyId). Upstream (AllocationSweep, SweepStudyConfig) is sealed/stable per build; recomputing this per-row via nested calc_* calls was measured to fan out to 22.5s for a 242-study corpus scan with zero memoization — materialized here instead of left as a live calculated field. See MaterializedEntities.
  t.sweep_corrected_gap_max,                                                    -- Principled materialization (refresh_sweep_study_summary()). Maximum SweepCorrectedGap across all allocation fractions for this study = MAXIFS(AllocationSweep[SweepCorrectedGap], AllocationSweep[StudyId], SweepStudyId). See CorrectedGapConstant for why this is materialized rather than calculated.
  t.sweep_corrected_gap_min,                                                    -- Principled materialization (refresh_sweep_study_summary()). Minimum SweepCorrectedGap across all allocation fractions for this study = MINIFS(AllocationSweep[SweepCorrectedGap], AllocationSweep[StudyId], SweepStudyId). See CorrectedGapConstant for why this is materialized rather than calculated.
  t.sweep_corrected_gap_range,                                                  -- Principled materialization (refresh_sweep_study_summary()). Range of SweepCorrectedGap across the sweep = SweepCorrectedGapMax - SweepCorrectedGapMin. Should be effectively zero (< 0.0001) for all studies if CorrectedGap is truly allocation-free. See CorrectedGapConstant for why this is materialized rather than calculated.
  t.sweep_pooled_gap_max,                                                       -- Principled materialization (refresh_sweep_study_summary()). Maximum SweepPooledGap across all allocation fractions for this study = MAXIFS(AllocationSweep[SweepPooledGap], AllocationSweep[StudyId], SweepStudyId). See CorrectedGapConstant for why this is materialized rather than calculated.
  t.sweep_pooled_gap_min,                                                       -- Principled materialization (refresh_sweep_study_summary()). Minimum SweepPooledGap across all allocation fractions for this study = MINIFS(AllocationSweep[SweepPooledGap], AllocationSweep[StudyId], SweepStudyId). See CorrectedGapConstant for why this is materialized rather than calculated.
  t.sweep_pooled_gap_range,                                                     -- Principled materialization (refresh_sweep_study_summary()). Range of SweepPooledGap across the sweep = SweepPooledGapMax - SweepPooledGapMin. Should be large for Type A/B studies (pooled gap wanders) and smaller for Type D (balanced allocation = less wandering). See CorrectedGapConstant for why this is materialized rather than calculated.
  t.pooled_gap_crosses_zero,                                                    -- Principled materialization (refresh_sweep_study_summary()). TRUE when SweepPooledGapMin < 0 and SweepPooledGapMax > 0 — the pooled gap changes sign somewhere in the sweep, meaning the paradox can be created or destroyed by pure allocation. See CorrectedGapConstant for why this is materialized rather than calculated.
  calc_sweep_study_summary_invariant_witness(t.sweep_study_id) AS invariant_witness,-- Summary witness statement: PASS if CorrectedGap is invariant (range < 0.0001), FAIL otherwise.
  calc_sweep_study_summary_sweep_stratum_label(t.sweep_study_id) AS sweep_stratum_label-- Which stratum is being swept for this study.
FROM sweep_study_summary t;

-- ----------------------------------------------------------------------------
-- vw_research_traditions: Table: ResearchTraditions — the six scholarly lineages that have engaged with Simpson's Paradox. Each row is a named intellectual tradition, not a specific paper or result.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_research_traditions CASCADE;
CREATE VIEW vw_research_traditions WITH (security_invoker = ON) AS
SELECT
  t.tradition_id,                                                               -- Slug identifier, e.g. tradition-historical.
  t.name,                                                                       -- Short display name for the tradition.
  t.era,                                                                        -- Approximate active period, e.g. "1899–1972".
  t.core_concern,                                                               -- The central question this tradition asks about the paradox.
  t.primary_venue,                                                              -- Where this tradition publishes (journal, conference, book series).
  t.key_claim,                                                                  -- The tradition's signature thesis or resolution strategy.
  t.open_question,                                                              -- What this tradition leaves unresolved or contested.
  t.verified_by_deep_research,                                                  -- True if the 2026-06-28 adversarial deep-research pass confirmed the tradition at high confidence.
  t.illustrated_by_study,                                                       -- FK → Studies.StudyId. The study in this model that most vividly illustrates this tradition's characteristic concern or resolution strategy.
  t.supporting_conclusion,                                                      -- FK → Conclusions.ConclusionId. The conclusion in this model that most directly validates or advances this tradition's central claim about Simpson's Paradox.
  calc_research_traditions_illustrated_by_study_title(t.tradition_id) AS illustrated_by_study_title,-- Lookup: Studies.Title via IllustratedByStudy.
  calc_research_traditions_illustrated_by_study_source(t.tradition_id) AS illustrated_by_study_source,-- Lookup: Studies.Source via IllustratedByStudy — the citation for the study that best illustrates this tradition.
  calc_research_traditions_illustrated_by_study_distortion_type(t.tradition_id) AS illustrated_by_study_distortion_type,-- Lookup: TreatmentRankings.DistortionType for the illustrated study.
  calc_research_traditions_supporting_conclusion_title(t.tradition_id) AS supporting_conclusion_title,-- Lookup: Conclusions.Title via SupportingConclusion.
  calc_research_traditions_supporting_conclusion_category(t.tradition_id) AS supporting_conclusion_category,-- Lookup: Conclusions.Category via SupportingConclusion.
  calc_research_traditions_researcher_count(t.tradition_id) AS researcher_count,-- Count of researchers in this tradition.
  calc_research_traditions_study_count(t.tradition_id) AS study_count,          -- Count of studies in this model whose TraditionId matches this tradition.
  calc_research_traditions_loop_count(t.tradition_id) AS loop_count             -- Count of Leopold Loops that drew primarily on this tradition's conceptual vocabulary.
FROM research_traditions t;

-- ----------------------------------------------------------------------------
-- vw_researchers: Table: Researchers — individuals who have made named, verified contributions to understanding Simpson's Paradox. Linked to ResearchTraditions by TraditionId.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_researchers CASCADE;
CREATE VIEW vw_researchers WITH (security_invoker = ON) AS
SELECT
  t.researcher_id,                                                              -- Slug, e.g. researcher-pearson.
  t.name,                                                                       -- Full name as commonly cited.
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId
  t.active_period,                                                              -- Approximate years of relevant work, e.g. "1899".
  t.affiliation,                                                                -- Primary institutional affiliation for the relevant work.
  t.key_contribution,                                                           -- One-sentence description of their specific contribution to the paradox literature.
  t.signature_work,                                                             -- The canonical paper or book most associated with their contribution.
  t.relation_to_hannan_pearl,                                                   -- How this researcher's line of work relates to or differs from Hannan (aggregation bias) and Pearl (DAG/do-calculus).
  t.verified_by_deep_research,                                                  -- True if the 2026-06-28 adversarial deep-research pass confirmed this person at high confidence.
  t.confidence_level,                                                           -- high | medium | unverified — matches deep-research vote outcome.
  t.canonical_study_id,                                                         -- FK → Studies.StudyId. The study in this model that best illustrates this researcher's specific contribution to the Simpson's Paradox literature.
  t.illustrates_conclusion,                                                     -- FK → Conclusions.ConclusionId. The conclusion in this model that this researcher's work directly supports, challenges, or frames.
  calc_researchers_tradition_name(t.researcher_id) AS tradition_name,           -- Lookup: ResearchTraditions.Name via TraditionId.
  calc_researchers_tradition_era(t.researcher_id) AS tradition_era,             -- Lookup: ResearchTraditions.Era via TraditionId.
  calc_researchers_canonical_study_title(t.researcher_id) AS canonical_study_title,-- Lookup: Studies.Title via CanonicalStudyId.
  calc_researchers_canonical_study_distortion_type(t.researcher_id) AS canonical_study_distortion_type,-- Lookup: TreatmentRankings.DistortionType for the canonical study — the geometric type of paradox this researcher's work exemplifies.
  calc_researchers_canonical_study_policy_implication(t.researcher_id) AS canonical_study_policy_implication,-- Lookup: TreatmentRankings.CorrectedPolicyImplication for the canonical study.
  calc_researchers_illustrates_conclusion_title(t.researcher_id) AS illustrates_conclusion_title,-- Lookup: Conclusions.Title via IllustratesConclusion.
  calc_researchers_tradition_key_claim_summary(t.researcher_id) AS tradition_key_claim_summary-- Lookup: ResearchTraditions.KeyClaim via TraditionId — the tradition's signature thesis this researcher contributed to.
FROM researchers t;

-- ----------------------------------------------------------------------------
-- vw_synthetic_phase: Table: SyntheticPhase — a parametric grid of canonical 2×2 synthetic studies at controlled (ParamStratumFraction, ParamStratumGap1, ParamStratumGap2, ParamAllocationBias) coordinates. Stratum 1 is the hard stratum (base rate 0.45); stratum 2 is easy (base rate 0.75). Each row constructs cell counts from the parameters and derives PhaseDistortionType using the same geometric classification as TreatmentRankings. This maps the A/B/C+/C-/D phase boundaries algebraically — independent of empirical corpus data.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_synthetic_phase CASCADE;
CREATE VIEW vw_synthetic_phase WITH (security_invoker = ON) AS
SELECT
  t.phase_id,                                                                   -- Unique grid-point identifier encoding (w, g1, g2, b) coordinates.
  calc_synthetic_phase_name(t.phase_id) AS name,                                -- Display label.
  t.param_stratum_fraction,                                                     -- w — fraction of total cases in the hard (stratum-1) subgroup. Range 0.30–0.75 in this grid.
  t.param_stratum_gap1,                                                         -- g1 — signed treatment advantage (rate_A − rate_B) in the hard stratum. Positive means A wins stratum 1.
  t.param_stratum_gap2,                                                         -- g2 — signed treatment advantage in the easy stratum. Negative g2 enables type-B (partial reversal) cells.
  t.param_allocation_bias,                                                      -- b — allocation bias in stratum 1: extra fraction of stratum-1 cases assigned to treatment A above 50/50. Range 0.00–0.95.
  calc_synthetic_phase_phase_s1_total(t.phase_id) AS phase_s1_total,            -- Total cases in stratum 1 = ROUND(200 × ParamStratumFraction).
  calc_synthetic_phase_phase_na1(t.phase_id) AS phase_na1,                      -- Treatment-A cases in stratum 1.
  calc_synthetic_phase_phase_nb1(t.phase_id) AS phase_nb1,                      -- Treatment-B cases in stratum 1.
  calc_synthetic_phase_phase_na2(t.phase_id) AS phase_na2,                      -- Treatment-A cases in stratum 2.
  calc_synthetic_phase_phase_nb2(t.phase_id) AS phase_nb2,                      -- Treatment-B cases in stratum 2.
  calc_synthetic_phase_phase_rate_a1(t.phase_id) AS phase_rate_a1,              -- Success rate for A in hard stratum.
  calc_synthetic_phase_phase_rate_b1(t.phase_id) AS phase_rate_b1,              -- Success rate for B in hard stratum.
  calc_synthetic_phase_phase_rate_a2(t.phase_id) AS phase_rate_a2,              -- Success rate for A in easy stratum.
  calc_synthetic_phase_phase_rate_b2(t.phase_id) AS phase_rate_b2,              -- Success rate for B in easy stratum.
  calc_synthetic_phase_phase_pooled_rate_a(t.phase_id) AS phase_pooled_rate_a,  -- Pooled success rate for treatment A.
  calc_synthetic_phase_phase_pooled_rate_b(t.phase_id) AS phase_pooled_rate_b,  -- Pooled success rate for treatment B.
  calc_synthetic_phase_phase_signed_pooled_gap(t.phase_id) AS phase_signed_pooled_gap,-- Pooled rate gap (A minus B).
  calc_synthetic_phase_phase_corrected_gap(t.phase_id) AS phase_corrected_gap,  -- Allocation-free equal-weight gap = w×g1 + (1−w)×g2.
  calc_synthetic_phase_phase_strata_won_by_loser(t.phase_id) AS phase_strata_won_by_loser,-- Count of strata whose per-stratum winner disagrees with the pooled winner.
  calc_synthetic_phase_phase_reversal_intensity(t.phase_id) AS phase_reversal_intensity,-- PhaseStrataWonByLoser / 2 for this 2-stratum template.
  calc_synthetic_phase_phase_is_sign_flip(t.phase_id) AS phase_is_sign_flip,    -- TRUE when equal-weight and pooled gaps have opposite signs.
  calc_synthetic_phase_phase_allocation_distortion(t.phase_id) AS phase_allocation_distortion,-- |PhaseCorrectedGap − PhaseSignedPooledGap|.
  calc_synthetic_phase_phase_distortion_type(t.phase_id) AS phase_distortion_type-- Five-type geometric classification at this parameter point.
FROM synthetic_phase t;

-- ----------------------------------------------------------------------------
-- vw_phase_diagram_summary: Table: PhaseDiagramSummary — one row summarising the SyntheticPhase grid. Witnesses that all five DistortionType cells (A, B, C+, C-, D) are nonempty in parameter space.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_phase_diagram_summary CASCADE;
CREATE VIEW vw_phase_diagram_summary WITH (security_invoker = ON) AS
SELECT
  t.phase_diagram_id,                                                           -- Unique identifier for this phase diagram instance.
  calc_phase_diagram_summary_name(t.phase_diagram_id) AS name,                  -- Display label.
  calc_phase_diagram_summary_phase_point_count(t.phase_diagram_id) AS phase_point_count,-- Total grid points in SyntheticPhase (sum of type counts). Refreshed from vw_synthetic_phase by 05b-customize-data.sql.
  t.phase_type_a_count,                                                         -- Grid points classified as type A. Populated from vw_synthetic_phase by 05b-customize-data.sql.
  t.phase_type_b_count,                                                         -- Grid points classified as type B. Populated from vw_synthetic_phase by 05b-customize-data.sql.
  t.phase_type_c_plus_count,                                                    -- Grid points classified as type C+. Populated from vw_synthetic_phase by 05b-customize-data.sql.
  t.phase_type_c_minus_count,                                                   -- Grid points classified as type C-. Populated from vw_synthetic_phase by 05b-customize-data.sql.
  t.phase_type_d_count,                                                         -- Grid points classified as type D. Populated from vw_synthetic_phase by 05b-customize-data.sql.
  calc_phase_diagram_summary_all_five_types_present(t.phase_diagram_id) AS all_five_types_present,-- TRUE when every DistortionType cell has at least one grid point.
  calc_phase_diagram_summary_phase_taxonomy_witness(t.phase_diagram_id) AS phase_taxonomy_witness,-- Human-readable witness string of type counts across the grid.
  calc_phase_diagram_summary_phase_witness_note(t.phase_diagram_id) AS phase_witness_note-- PASS/FAIL summary for taxonomy completeness.
FROM phase_diagram_summary t;

-- ----------------------------------------------------------------------------
-- vw_ingestion_protocol: Table: IngestionProtocol — the minimal formal contract for adding a new 2×K study to the corpus.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ingestion_protocol CASCADE;
CREATE VIEW vw_ingestion_protocol WITH (security_invoker = ON) AS
SELECT
  t.protocol_id,                                                                -- Unique slug for this contract item.
  calc_ingestion_protocol_name(t.protocol_id) AS name,                          -- Display label.
  t.rule_type,                                                                  -- required-input | structural | inclusion | exclusion | adapter-metadata
  t.target_table,                                                               -- Rulebook table this item applies to.
  t.field_name,                                                                 -- Column name when RuleType=required-input.
  t.requirement_statement,                                                      -- Plain-English statement of the requirement.
  t.mechanical_check,                                                           -- How to verify compliance before classification.
  t.sort_order                                                                  -- Display order in the ingestion checklist.
FROM ingestion_protocol t;

-- ----------------------------------------------------------------------------
-- vw_ingestion_summary: Table: IngestionSummary — witnesses that the current corpus satisfies the IngestionProtocol contract.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_ingestion_summary CASCADE;
CREATE VIEW vw_ingestion_summary WITH (security_invoker = ON) AS
SELECT
  t.ingestion_summary_id,                                                       -- Unique identifier.
  calc_ingestion_summary_name(t.ingestion_summary_id) AS name,                  -- Display label.
  calc_ingestion_summary_protocol_item_count(t.ingestion_summary_id) AS protocol_item_count,-- Total contract items. Fixed loop-90: COUNTIFS(...,"<>") mistranslates to a literal '<>' string-equality filter (a known transpiler bug) instead of IS NOT NULL, always returning 0; replaced with bare COUNT(), which transpiles correctly.
  calc_ingestion_summary_corpus_cell_count(t.ingestion_summary_id) AS corpus_cell_count,-- Total CaseCell rows. Fixed loop-90 (see ProtocolItemCount).
  calc_ingestion_summary_valid_cell_count(t.ingestion_summary_id) AS valid_cell_count,-- Valid CaseCells.
  calc_ingestion_summary_all_cells_valid(t.ingestion_summary_id) AS all_cells_valid,-- Every cell passes validity predicate.
  calc_ingestion_summary_study_count(t.ingestion_summary_id) AS study_count,    -- Count of studies subject to the ingestion contract (excludes control studies, loop-92 -- control studies were never encoded with paired treatment arms, so IngestionCellParity is structurally undefined for them, not a real ingestion defect).
  calc_ingestion_summary_structural_compliant_count(t.ingestion_summary_id) AS structural_compliant_count,-- Studies with IngestionCellParity.
  calc_ingestion_summary_all_studies_structural(t.ingestion_summary_id) AS all_studies_structural,-- All studies structurally valid.
  calc_ingestion_summary_real_study_count(t.ingestion_summary_id) AS real_study_count,-- Non-synthetic, non-control studies (loop-92 -- control studies were never encoded with paired treatment arms, so they are outside the ingestion contract's scope, same as StructuralCompliantCount's StudyCount).
  calc_ingestion_summary_real_fully_compliant_count(t.ingestion_summary_id) AS real_fully_compliant_count,-- Real studies with IngestionCompliance=all.
  calc_ingestion_summary_all_real_studies_compliant(t.ingestion_summary_id) AS all_real_studies_compliant,-- All real studies fully compliant.
  calc_ingestion_summary_ingestion_contract_passes(t.ingestion_summary_id) AS ingestion_contract_passes,-- Full contract passes.
  calc_ingestion_summary_ingestion_witness_note(t.ingestion_summary_id) AS ingestion_witness_note-- PASS/FAIL summary.
FROM ingestion_summary t;

-- ----------------------------------------------------------------------------
-- vw_candidate_study_catalog: Table: CandidateStudyCatalog — curated backlog of published Simpson's-paradox-eligible studies. Tracks import status, expected distortion type, and encoding metadata before CaseCells exist.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_candidate_study_catalog CASCADE;
CREATE VIEW vw_candidate_study_catalog WITH (security_invoker = ON) AS
SELECT
  t.candidate_id,                                                               -- Unique slug for this catalog entry.
  calc_candidate_study_catalog_name(t.candidate_id) AS name,                    -- Display label.
  t.proposed_study_id,                                                          -- Stable slug to assign in Studies when imported.
  t.title,                                                                      -- Human-readable study title.
  t.citation,                                                                   -- Primary publication citation.
  t.source_url,                                                                 -- URL to source paper or data.
  t.domain,                                                                     -- Domain tag: medicine, epidemiology, legal, sports, education, economics, social-science.
  t.stratum_variable_name,                                                      -- Pre-registered stratifying variable name for encoding.
  t.expected_distortion_type,                                                   -- Hypothesized DistortionType after classification: A, B, C+, C-, D, or unknown.
  t.ingestion_status,                                                           -- imported | candidate | blocked | rejected
  t.priority,                                                                   -- 1=high priority encode next; 5=blocked/duplicate.
  t.stratum_count_estimate,                                                     -- Expected number of strata (minimum 2).
  t.data_source_note,                                                           -- Where to find cell counts and encoding notes.
  t.linked_study_id,                                                            -- Studies.StudyId when IngestionStatus=imported.
  t.publication_year,                                                           -- Publication year when known.
  calc_candidate_study_catalog_is_ready_to_encode(t.candidate_id) AS is_ready_to_encode,-- TRUE when candidate has citation, proposed id, and stratum variable — ready for an import session.
  calc_candidate_study_catalog_is_imported(t.candidate_id) AS is_imported,      -- TRUE when already in corpus.
  calc_candidate_study_catalog_observed_distortion_type(t.candidate_id) AS observed_distortion_type,-- Actual DistortionType from TreatmentRankings when imported.
  calc_candidate_study_catalog_type_prediction_match(t.candidate_id) AS type_prediction_match,-- TRUE when observed type matches expected (imported rows only).
  calc_candidate_study_catalog_expected_sign_flip(t.candidate_id) AS expected_sign_flip,-- TRUE when curator tagged ExpectedDistortionType as A or B (sign-flip expectation).
  calc_candidate_study_catalog_observed_sign_flip_type(t.candidate_id) AS observed_sign_flip_type,-- TRUE when observed DistortionType is A or B (imported rows only).
  calc_candidate_study_catalog_sign_flip_prediction_match(t.candidate_id) AS sign_flip_prediction_match,-- TRUE when Expected A∪B and observed is A∪B — weaker flip-type prediction test.
  t.data_acquisition_status,                                                    -- not_started | downloaded | manual_only | blocked
  t.reversal_mechanism,                                                         -- Plain-language reversal mechanism from expansion plan.
  t.paradox_confirmation,                                                       -- confirmed | plausible | pending | not_applicable
  t.expansion_wave,                                                             -- Catalog wave tag; loop-67 expansion rows = expansion-wave-1.
  calc_candidate_study_catalog_is_data_ready(t.candidate_id) AS is_data_ready   -- TRUE when stratified data is downloaded or available from published tables.
FROM candidate_study_catalog t;

-- ----------------------------------------------------------------------------
-- vw_corpus_catalog_summary: Table: CorpusCatalogSummary — one row witnessing import-backlog readiness for bulk encoding sessions.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_corpus_catalog_summary CASCADE;
CREATE VIEW vw_corpus_catalog_summary WITH (security_invoker = ON) AS
SELECT
  t.catalog_summary_id,                                                         -- Unique identifier.
  calc_corpus_catalog_summary_name(t.catalog_summary_id) AS name,               -- Display label.
  calc_corpus_catalog_summary_total_catalog_entries(t.catalog_summary_id) AS total_catalog_entries,-- All catalog rows. Fixed loop-90 (see IngestionSummary.ProtocolItemCount for why COUNTIFS(...,"<>") is unsafe).
  calc_corpus_catalog_summary_imported_count(t.catalog_summary_id) AS imported_count,-- Rows already imported.
  calc_corpus_catalog_summary_candidate_count(t.catalog_summary_id) AS candidate_count,-- Rows queued for import.
  calc_corpus_catalog_summary_blocked_count(t.catalog_summary_id) AS blocked_count,-- Duplicate or blocked rows.
  calc_corpus_catalog_summary_ready_to_encode_count(t.catalog_summary_id) AS ready_to_encode_count,-- Candidates passing IsReadyToEncode.
  calc_corpus_catalog_summary_high_priority_count(t.catalog_summary_id) AS high_priority_count,-- Candidates with Priority <= 2.
  calc_corpus_catalog_summary_import_session_ready(t.catalog_summary_id) AS import_session_ready,-- TRUE when backlog is large enough for a bulk import session.
  calc_corpus_catalog_summary_type_prediction_match_count(t.catalog_summary_id) AS type_prediction_match_count,-- Imported catalog rows where ObservedDistortionType exactly matches ExpectedDistortionType.
  calc_corpus_catalog_summary_type_prediction_mismatch_count(t.catalog_summary_id) AS type_prediction_mismatch_count,-- Imported catalog rows where exact type prediction failed.
  calc_corpus_catalog_summary_sign_flip_prediction_eligible_count(t.catalog_summary_id) AS sign_flip_prediction_eligible_count,-- Imported rows where ExpectedDistortionType was A or B.
  calc_corpus_catalog_summary_sign_flip_prediction_match_count(t.catalog_summary_id) AS sign_flip_prediction_match_count,-- Expected A∪B rows where observed type is also A∪B.
  calc_corpus_catalog_summary_type_prediction_match_rate(t.catalog_summary_id) AS type_prediction_match_rate,-- Exact-match rate across imported catalog rows.
  calc_corpus_catalog_summary_sign_flip_prediction_match_rate(t.catalog_summary_id) AS sign_flip_prediction_match_rate,-- Sign-flip-type match rate among Expected A∪B rows.
  calc_corpus_catalog_summary_catalog_witness_note(t.catalog_summary_id) AS catalog_witness_note,-- Human-readable readiness summary.
  calc_corpus_catalog_summary_catalog_prediction_witness_note(t.catalog_summary_id) AS catalog_prediction_witness_note,-- Loop-65 type-prediction audit summary.
  calc_corpus_catalog_summary_data_ready_count(t.catalog_summary_id) AS data_ready_count,-- Candidates with IsDataReady=TRUE.
  calc_corpus_catalog_summary_encode_pipeline_ready_count(t.catalog_summary_id) AS encode_pipeline_ready_count,-- Candidates both data-ready and encode-ready.
  calc_corpus_catalog_summary_expansion_candidate_count(t.catalog_summary_id) AS expansion_candidate_count-- Loop-67 expansion-wave-1 candidates.
FROM corpus_catalog_summary t;

-- ----------------------------------------------------------------------------
-- vw_domain_expansion_targets: Table: DomainExpansionTargets — per-domain corpus growth targets for bulk import prioritisation.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_domain_expansion_targets CASCADE;
CREATE VIEW vw_domain_expansion_targets WITH (security_invoker = ON) AS
SELECT
  t.domain_target_id,                                                           -- Unique slug.
  calc_domain_expansion_targets_name(t.domain_target_id) AS name,               -- Display label.
  t.domain,                                                                     -- Domain tag matching Studies.Domain.
  t.legacy_domain_alias,                                                        -- Studies.Domain slug for legacy imported corpus rows.
  t.target_min_count,                                                           -- Minimum real studies desired in this domain.
  calc_domain_expansion_targets_current_imported_count(t.domain_target_id) AS current_imported_count,-- Real studies in corpus matching LegacyDomainAlias (or Domain when no alias).
  calc_domain_expansion_targets_candidate_queued_count(t.domain_target_id) AS candidate_queued_count,-- Catalog candidates in this domain.
  calc_domain_expansion_targets_projected_count(t.domain_target_id) AS projected_count,-- Current + queued candidates.
  calc_domain_expansion_targets_gap_count(t.domain_target_id) AS gap_count,     -- Studies still needed to hit target after queued imports.
  calc_domain_expansion_targets_is_under_represented(t.domain_target_id) AS is_under_represented-- TRUE when projected count still below target.
FROM domain_expansion_targets t;

-- ----------------------------------------------------------------------------
-- vw_study_import_template: Table: StudyImportTemplate — mechanical checklist of rulebook rows to create when importing one catalog candidate.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_study_import_template CASCADE;
CREATE VIEW vw_study_import_template WITH (security_invoker = ON) AS
SELECT
  t.template_step_id,                                                           -- Unique slug.
  calc_study_import_template_name(t.template_step_id) AS name,                  -- Display label.
  t.sort_order,                                                                 -- Order to execute during import.
  t.target_table,                                                               -- Rulebook table to write.
  t.row_description,                                                            -- What rows to create.
  t.required_fields,                                                            -- Key columns that must be populated.
  t.mechanical_check                                                            -- How to verify step complete.
FROM study_import_template t;

-- ----------------------------------------------------------------------------
-- vw_sweep_study_config: Table: SweepStudyConfig — per-study allocation-sweep parameters derived from CaseCells. Picks the highest-allocation-bias stratum to sweep; holds all other strata fixed.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_sweep_study_config CASCADE;
CREATE VIEW vw_sweep_study_config WITH (security_invoker = ON) AS
SELECT
  t.config_id,                                                                  -- Unique slug; mirrors StudyId.
  calc_sweep_study_config_name(t.config_id) AS name,                            -- Display label.
  t.study_id,                                                                   -- FK to Studies.StudyId.
  t.sweep_stratum_label,                                                        -- Stratum whose A/B allocation is swept (highest |AllocationBias| in original data).
  t.n_sweep_stratum_total,                                                      -- Total cases in the sweep stratum (fixed across sweep rows).
  t.sweep_rate_a,                                                               -- Success rate for treatment A in the sweep stratum.
  t.sweep_rate_b,                                                               -- Success rate for treatment B in the sweep stratum.
  t.n_fixed_a,                                                                  -- A cases in all non-swept strata (fixed).
  t.n_fixed_b,                                                                  -- B cases in all non-swept strata (fixed).
  t.fixed_rate_a,                                                               -- Weighted success rate for A in fixed strata.
  t.fixed_rate_b,                                                               -- Weighted success rate for B in fixed strata.
  t.original_alloc_fraction_a,                                                  -- Observed fraction of sweep-stratum cases assigned to treatment A.
  t.sweep_corrected_gap                                                         -- Allocation-free gap: sum_s (n_s/N)*(rate_As-rate_Bs). Invariant under within-stratum reallocation.
FROM sweep_study_config t;

-- ----------------------------------------------------------------------------
-- vw_substrate_conformance_fields: Table: SubstrateConformanceFields — cross-substrate OWL-SHACL vs Postgres compare manifest for owl/reason.py. Rows with AssertFromPostgres=TRUE are asserted as leaf facts before SHACL fixpoint (OWL transpiler lacks CONSTRUCT for nested IF chains).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_substrate_conformance_fields CASCADE;
CREATE VIEW vw_substrate_conformance_fields WITH (security_invoker = ON) AS
SELECT
  t.field_id,                                                                   -- Unique slug.
  calc_substrate_conformance_fields_name(t.field_id) AS name,                   -- Display label.
  t.source_table,                                                               -- TreatmentRankings | StratumSummaries | StratumVariables
  t.field_name,                                                                 -- PascalCase rulebook field name.
  t.pg_column,                                                                  -- snake_case vw_* column.
  t.owl_local_name,                                                             -- camelCase OWL property local name.
  t.data_type,                                                                  -- float | int | bool | str
  t.assert_from_postgres,                                                       -- TRUE when OWL cannot derive this field yet and Postgres value is asserted before SHACL fixpoint.
  t.in_compare_set                                                              -- TRUE when reason.py diffs this field between substrates.
FROM substrate_conformance_fields t;

-- ----------------------------------------------------------------------------
-- vw_discovery_hypotheses: Table: DiscoveryHypotheses — pre-registered empirical claims tested against the corpus at loop-61. Each row states an expected pattern before querying the DAG.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_discovery_hypotheses CASCADE;
CREATE VIEW vw_discovery_hypotheses WITH (security_invoker = ON) AS
SELECT
  t.hypothesis_id,                                                              -- Unique slug (e.g. H-latent-d).
  calc_discovery_hypotheses_name(t.hypothesis_id) AS name,                      -- Display label.
  t.statement,                                                                  -- Natural-language claim under test.
  t.expected_outcome,                                                           -- Pass criterion in plain language.
  t.registered_in_loop,                                                         -- LoopId where this hypothesis was registered.
  t.tradition_id,                                                               -- FK → ResearchTraditions.TraditionId.
  t.epistemic_tier                                                              -- consistency-check (definition-linked regression) | corpus-hypothesis (contingent corpus pattern)
FROM discovery_hypotheses t;

-- ----------------------------------------------------------------------------
-- vw_discovery_findings: Table: DiscoveryFindings — witnessed outcomes for each pre-registered DiscoveryHypothesis. IsConfirmed is computed live from ModelSummary aggregates.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_discovery_findings CASCADE;
CREATE VIEW vw_discovery_findings WITH (security_invoker = ON) AS
SELECT
  t.finding_id,                                                                 -- Unique slug; one row per hypothesis.
  calc_discovery_findings_name(t.finding_id) AS name,                           -- Display label.
  t.hypothesis_id,                                                              -- FK → DiscoveryHypotheses.HypothesisId.
  calc_discovery_findings_hypothesis_statement(t.finding_id) AS hypothesis_statement,-- Lookup: DiscoveryHypotheses.Statement.
  calc_discovery_findings_observed_metric(t.finding_id) AS observed_metric,     -- Witnessed metric value from ModelSummary for this hypothesis.
  calc_discovery_findings_is_confirmed(t.finding_id) AS is_confirmed,           -- TRUE when the witnessed metric satisfies the pre-registered ExpectedOutcome.
  calc_discovery_findings_evidence(t.finding_id) AS evidence,                   -- Pass/fail witness string for UI and conclusions.
  t.witnessed_in_loop                                                           -- LoopId where this finding was witnessed.
FROM discovery_findings t;

-- ----------------------------------------------------------------------------
-- vw_corpus_domains: Table: CorpusDomains — canonical expansion-domain slugs from corpus-expansion-plan.md (loop-67).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_corpus_domains CASCADE;
CREATE VIEW vw_corpus_domains WITH (security_invoker = ON) AS
SELECT
  t.domain_id,                                                                  -- Unique slug (matches CandidateStudyCatalog.Domain for expansion wave).
  calc_corpus_domains_name(t.domain_id) AS name,                                -- Display label.
  t.display_name,                                                               -- Human-readable domain name.
  t.expansion_target,                                                           -- Target study count from corpus-expansion-plan.md.
  t.legacy_studies_domain,                                                      -- Studies.Domain alias for counting already-imported corpus rows.
  t.plan_source_section                                                         -- Section heading in corpus-expansion-plan.md.
FROM corpus_domains t;

-- ----------------------------------------------------------------------------
-- vw_confounder_identities: Table: ConfounderIdentities — canonical cross-study archetypes for stratum variables. Each identity names a reusable confounding mechanism accountable across the corpus (loop-80).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_confounder_identities CASCADE;
CREATE VIEW vw_confounder_identities WITH (security_invoker = ON) AS
SELECT
  t.confounder_identity_id,                                                     -- Unique slug (e.g. id-age-composition).
  calc_confounder_identities_name(t.confounder_identity_id) AS name,            -- Display label.
  t.display_name,                                                               -- Human-readable archetype name.
  t.mechanism_class,                                                            -- Mechanism taxonomy token.
  t.description,                                                                -- Narrative description of confounding mechanism.
  t.policy_default,                                                             -- Default analytic policy for this confounding archetype.
  calc_confounder_identities_study_count(t.confounder_identity_id) AS study_count-- Studies with a StratumVariable mapped to this identity.
FROM confounder_identities t;

-- ----------------------------------------------------------------------------
-- vw_stratum_variable_identity_maps: Table: StratumVariableIdentityMaps — many-to-one map from per-study StratumVariables to canonical ConfounderIdentities (loop-80).
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_stratum_variable_identity_maps CASCADE;
CREATE VIEW vw_stratum_variable_identity_maps WITH (security_invoker = ON) AS
SELECT
  t.map_id,                                                                     -- Unique slug.
  calc_stratum_variable_identity_maps_name(t.map_id) AS name,                   -- Display label.
  t.stratum_variable,                                                           -- FK → StratumVariables.
  t.confounder_identity,                                                        -- FK → ConfounderIdentities.
  t.variable_name_normalized                                                    -- Lowercase normalized variable token for dedup audit.
FROM stratum_variable_identity_maps t;

-- ----------------------------------------------------------------------------
-- vw_identity_cluster_summaries: Table: IdentityClusterSummaries — witnessed geometry rollup per ConfounderIdentity (manifest flip, latent-D, avg distortion) — loop-80 open-question substrate.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_identity_cluster_summaries CASCADE;
CREATE VIEW vw_identity_cluster_summaries WITH (security_invoker = ON) AS
SELECT
  t.identity_cluster_id,                                                        -- Unique slug; one row per ConfounderIdentity cluster.
  calc_identity_cluster_summaries_name(t.identity_cluster_id) AS name,          -- Display label.
  t.confounder_identity,                                                        -- FK → ConfounderIdentities.
  calc_identity_cluster_summaries_display_name(t.identity_cluster_id) AS display_name,-- Lookup archetype display name.
  t.study_count,                                                                -- Real studies in cluster (customize SQL).
  t.manifest_flip_count,                                                        -- IsSignFlip=TRUE count in cluster.
  t.latent_flip_count,                                                          -- LatentFlipPotential=TRUE without manifest flip.
  t.type_d_count,                                                               -- Type-D studies in cluster.
  t.avg_allocation_distortion,                                                  -- Mean allocation distortion in cluster.
  t.latent_fraction_among_type_d,                                               -- Fraction of Type-D rows with LatentFlipPotential.
  t.domain_count,                                                               -- Distinct Studies.Domain values in cluster.
  calc_identity_cluster_summaries_manifest_flip_rate(t.identity_cluster_id) AS manifest_flip_rate-- ManifestFlipCount / StudyCount.
FROM identity_cluster_summaries t;

-- ----------------------------------------------------------------------------
-- vw_identity_domain_cells: View for IdentityDomainCells
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_identity_domain_cells CASCADE;
CREATE VIEW vw_identity_domain_cells WITH (security_invoker = ON) AS
SELECT
  t.cell_id,                                                                    -- Unique slug: identity-id + '-x-' + domain slug.
  calc_identity_domain_cells_name(t.cell_id) AS name,                           -- Display label.
  t.confounder_identity,                                                        -- FK → ConfounderIdentities.
  t.domain,                                                                     -- Studies.Domain value (e.g. medicine, epidemiology).
  t.study_count,                                                                -- Studies with this identity in this domain (customize SQL).
  t.manifest_flip_count,                                                        -- IsSignFlip=TRUE count in cell.
  t.latent_flip_count,                                                          -- LatentFlipPotential=TRUE without manifest flip.
  t.type_d_count,                                                               -- Type-D studies in cell.
  t.latent_fraction_among_type_d,                                               -- Fraction of Type-D rows with LatentFlipPotential in cell.
  calc_identity_domain_cells_manifest_flip_rate(t.cell_id) AS manifest_flip_rate,-- ManifestFlipCount / StudyCount.
  calc_identity_domain_cells_identity_display_name(t.cell_id) AS identity_display_name-- Lookup archetype display name.
FROM identity_domain_cells t;

-- ----------------------------------------------------------------------------
-- vw_confounder_distortion_timeline: Table: ConfounderDistortionTimeline -- derived geometry at the (ConfounderIdentity x ValidTimeDecade) grain. Each row aggregates the studies whose real-world cohort period (valid-time, not publication year) falls in that decade and that carry the given confounder archetype, tracking whether the corpus drifts toward clean Type-D (non-reversing, zero-allocation-distortion) outcomes over time and whether that drift is confounder-specific. Principled materialization per CLAUDE.md (N-way join over a sealed, bounded study set) -- refreshed via refresh_confounder_distortion_timeline(), same pattern as IdentityClusterSummaries/IdentityDomainCells.
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_confounder_distortion_timeline CASCADE;
CREATE VIEW vw_confounder_distortion_timeline WITH (security_invoker = ON) AS
SELECT
  t.cell_id,                                                                    -- Unique slug: confounder-identity-id + '-x-' + valid-time decade (e.g. id-disease-severity-x-1980).
  calc_confounder_distortion_timeline_name(t.cell_id) AS name,                  -- Display label.
  t.confounder_identity,                                                        -- FK -> ConfounderIdentities.
  t.valid_time_decade,                                                          -- Studies.ValidTimeDecade bucket this cell aggregates over (e.g. 1980 covers valid-time midpoints 1980-1989).
  t.study_count,                                                                -- Studies carrying this ConfounderIdentity whose ValidTimeDecade falls in this bucket (refresh_confounder_distortion_timeline()).
  t.type_d_count,                                                               -- Of those, count with TreatmentRankings.DistortionType = 'D' (clean, non-reversing).
  t.sign_flip_count,                                                            -- Of those, count with TreatmentRankings.IsSignFlip = TRUE.
  t.sum_signal_purity,                                                          -- Sum of TreatmentRankings.SignalPurity across cell studies (numerator for MeanSignalPurity; summed rather than pre-averaged so the aggregate survives refresh re-runs without drift).
  t.sum_allocation_distortion,                                                  -- Sum of TreatmentRankings.AllocationDistortion across cell studies (numerator for MeanAllocationDistortion).
  calc_confounder_distortion_timeline_type_d_fraction(t.cell_id) AS type_d_fraction,-- TypeDCount / StudyCount.
  calc_confounder_distortion_timeline_sign_flip_fraction(t.cell_id) AS sign_flip_fraction,-- SignFlipCount / StudyCount.
  calc_confounder_distortion_timeline_mean_signal_purity(t.cell_id) AS mean_signal_purity,-- SumSignalPurity / StudyCount.
  calc_confounder_distortion_timeline_mean_allocation_distortion(t.cell_id) AS mean_allocation_distortion,-- SumAllocationDistortion / StudyCount.
  calc_confounder_distortion_timeline_identity_display_name(t.cell_id) AS identity_display_name,-- Lookup: ConfounderIdentities.DisplayName via ConfounderIdentity.
  calc_confounder_distortion_timeline_mechanism_class(t.cell_id) AS mechanism_class,-- Lookup: ConfounderIdentities.MechanismClass via ConfounderIdentity — the archetype group used to test whether Type-D drift is confounder-specific.
  calc_confounder_distortion_timeline_identity_earliest_decade(t.cell_id) AS identity_earliest_decade,-- Earliest ValidTimeDecade present in this table for this ConfounderIdentity.
  calc_confounder_distortion_timeline_identity_latest_decade(t.cell_id) AS identity_latest_decade,-- Latest ValidTimeDecade present in this table for this ConfounderIdentity.
  calc_confounder_distortion_timeline_identity_earliest_type_d_fr(t.cell_id) AS identity_earliest_type_d_fraction,-- TypeDFraction of this ConfounderIdentity's earliest decade cell -- the start point for the drift comparison.
  calc_confounder_distortion_timeline_identity_latest_type_d_frac(t.cell_id) AS identity_latest_type_d_fraction,-- TypeDFraction of this ConfounderIdentity's latest decade cell -- the end point for the drift comparison.
  calc_confounder_distortion_timeline_drift_direction(t.cell_id) AS drift_direction-- rising | falling | flat | single-decade -- compares this ConfounderIdentity's earliest-decade TypeDFraction to its latest-decade TypeDFraction across the whole table (same value on every row for a given ConfounderIdentity by construction).
FROM confounder_distortion_timeline t;

-- ----------------------------------------------------------------------------
-- vw_corpus_balance: View for CorpusBalance
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
DROP VIEW IF EXISTS vw_corpus_balance CASCADE;
CREATE VIEW vw_corpus_balance WITH (security_invoker = ON) AS
SELECT
  t.balance_id,                                                                 -- Primary key (singleton: 'corpus-balance')
  calc_corpus_balance_name(t.balance_id) AS name,                               -- =BalanceId
  calc_corpus_balance_total_study_count(t.balance_id) AS total_study_count,     -- Total studies in corpus (Simpson + control). Fixed loop-90: was authored with COUNTA/bareword refs and an uppercase Formula key, which the transpiler cannot parse. COUNTIFS(...,"<>") also mistranslates (known transpiler bug: literal '<>' string instead of IS NOT NULL), so this is expressed as SimpsonStudyCount + ControlStudyCount instead.
  calc_corpus_balance_simpson_study_count(t.balance_id) AS simpson_study_count, -- Studies where IsControlStudy=FALSE. Fixed loop-90 (see TotalStudyCount).
  calc_corpus_balance_control_study_count(t.balance_id) AS control_study_count, -- Studies where IsControlStudy=TRUE. Fixed loop-90 (see TotalStudyCount).
  calc_corpus_balance_control_fraction(t.balance_id) AS control_fraction        -- ControlStudyCount / TotalStudyCount. Fixed loop-90 (see TotalStudyCount); returns 0 for the degenerate empty-corpus edge instead of "" (see TreatmentRankings.DistortionRatio for why IF(x=0,"",...) is unsafe on a numeric-typed field).
FROM corpus_balance t;

